            occasion: params.occasion,
            message: params.message,
            theme: params.theme,
            videoUrl: finalUrl,
            voice: params.voice
          };
        } else {
          // Save new record
          const docRef = await saveGreeting(user.uid, {
            userId: user.uid,
            occasion: params.occasion,
            message: params.message,
            theme: params.theme,
            videoUrl: finalUrl,
            voice: params.voice,
            createdAt: Date.now()
          });

          newRecord = {
            id: docRef.id,
            userId: user.uid,
            occasion: params.occasion,
            message: params.message,
            theme: params.theme,
            videoUrl: finalUrl,
            voice: params.voice,
            createdAt: Date.now()
          };
        }

        setEditingGreeting(null);
        loadData(user);
      } else {
        finalUrl = URL.createObjectURL(blob);
      }

      setCurrentResult({ 
        url: finalUrl, 
        params, 
        record: newRecord,
        audioUrl: audioBase64 
      });
      setAppState(AppState.SUCCESS);
    } catch (e: any) {
      console.error("Production Error:", e);
      const errorMsg = e.toString();

      if (errorMsg.includes("429") || errorMsg.toLowerCase().includes("quota") || errorMsg.toLowerCase().includes("limit exceeded")) {
        alert("Daily Production Quota Reached: Your Google Cloud project has hit its limit for today. You can request more in the Cloud Console > IAM & Admin > Quotas or wait until it resets at midnight.");
      } else if (errorMsg.includes("Requested entity was not found")) {
        setIsKeyConnected(false);
        if (window.aistudio) await window.aistudio.openSelectKey();
      } else {
        alert("Production Error: " + errorMsg);
      }

      setAppState(user ? AppState.GALLERY : AppState.IDLE);
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (window.confirm("Permanently delete this cinematic greeting?")) {
      try {
        await deleteGreeting(id);
        if (user) loadData(user);
      } catch (error) {
        console.error("Deletion failed:", error);
      }
    }
  };

  const handleEdit = (greeting: GreetingRecord) => {
    setEditingGreeting(greeting);
    setAppState(AppState.IDLE);
  };

  const handleSelectGreeting = (greeting: GreetingRecord) => {
    setCurrentResult({
      url: greeting.videoUrl,
      record: greeting,
      params: {
        occasion: greeting.occasion,
        message: greeting.message,
        theme: greeting.theme,
        voice: greeting.voice || VoiceGender.FEMALE, 
        userPhoto: null,
        model: VeoModel.VEO_FAST,
        aspectRatio: AspectRatio.LANDSCAPE,
        extended: false
      }
    });
    setAppState(AppState.SUCCESS);
  };

  const handleInternalShare = async (email: string) => {
    if (!currentResult?.record || !user) return;
    try {
      await sendToInternalUser(user.displayName || "A Friend", email, currentResult.record);
      alert("Sent! This greeting will appear in their library shortly.");
    } catch (err: any) {
      alert("Internal share failed: " + err.message);
    }
  };

  const handleNewScript = () => {
    setEditingGreeting(null);
    setAppState(AppState.IDLE);
  };

  return (
    <div className="min-h-screen bg-black text-white flex flex-col font-sans selection:bg-blue-600/30">
      {showApiKeyDialog && <ApiKeyDialog onContinue={() => {
        if (window.aistudio) {
          window.aistudio.openSelectKey();
          setIsKeyConnected(true);
          setShowApiKeyDialog(false);
        }
      }} />}

      <HelpModal isOpen={showHelpModal} onClose={() => setShowHelpModal(false)} />

      <header className="px-6 py-5 flex justify-between items-center border-b border-white/5 bg-black/95 backdrop-blur-xl sticky top-0 z-50">
        <div 
          className="flex items-center gap-2 cursor-pointer group" 
          onClick={() => setAppState(user ? AppState.GALLERY : AppState.AUTH)}
        >
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center font-bold text-xl shadow-[0_0_20px_rgba(37,99,235,0.4)] group-hover:scale-105 transition-transform text-white">
            eG
          </div>
          <div className="flex flex-col">
            <h1 className="text-2xl font-black tracking-tight text-white leading-none">eGreetz</h1>
            <div className="flex items-center gap-1.5 mt-1.5">
              <span className={`flex h-2 w-2 rounded-full ${isKeyConnected ? 'bg-green-500' : 'bg-yellow-500 animate-pulse'}`}></span>
              <span className="text-[10px] text-gray-400 font-black tracking-widest uppercase">
                {isKeyConnected ? 'Studio Ready' : 'Connect Key'}
              </span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-4">
          {user && (
            <button 
              onClick={handleRefresh}
              className="p-2 text-gray-400 hover:text-white transition-colors"
              title="Refresh Library"
            >
              <RefreshCw size={20} className={isLoading ? 'animate-spin' : ''} />
            </button>
          )}
          <button 
            onClick={() => setShowHelpModal(true)}
            className="p-2 text-gray-400 hover:text-white transition-colors"
            title="Help & Info"
          >
            <HelpCircle size={22} />
          </button>
          {user ? (
            <>
              <button 
                onClick={handleNewScript}
                className="flex items-center gap-2 px-6 py-2 bg-blue-600 rounded-full hover:bg-blue-500 transition-all font-bold text-sm text-white"
              >
                <Plus size={16} strokeWidth={3} /> New Script
              </button>
              <button onClick={logout} className="p-2 text-gray-500 hover:text-white transition-colors">
                <LogOut size={20} />
              </button>
            </>
          ) : (
            <button 
              onClick={loginWithGoogle}
              className="flex items-center gap-2 px-7 py-2.5 bg-white text-black font-black rounded-full hover:bg-gray-200 transition-all text-sm uppercase tracking-wider"
            >
              <LogIn size={16} strokeWidth={3} /> Login
            </button>
          )}
        </div>
      </header>

      <main className="flex-grow flex flex-col items-center p-6 w-full max-w-6xl mx-auto">
        {!isFirebaseReady && (
          <div className="w-full max-w-4xl mb-6 p-4 bg-red-900/10 border border-red-500/20 rounded-2xl flex items-center gap-3 text-red-200 text-sm">
            <AlertCircle size={20} className="text-red-400" />
            <span>Cloud Sync Inactive. Sharing is disabled. Please verify Firebase environment variables.</span>
          </div>
        )}

        {appState === AppState.AUTH && (
          <div className="flex-grow flex flex-col items-center justify-center text-center max-w-3xl animate-in fade-in zoom-in duration-1000">
            <h2 className="text-7xl font-black mb-8 leading-[1] text-white tracking-tighter">Cinematic <span className="text-blue-600">Reimagined.</span></h2>
            <p className="text-2xl text-gray-400 mb-12 leading-relaxed font-medium">Create and host Hollywood-grade video greetings. Permanent cloud storage ensures your links never expire.</p>
            <div className="flex flex-col sm:flex-row gap-4">
              <button 
                onClick={user ? handleNewScript : loginWithGoogle}
                className="px-16 py-6 bg-blue-600 rounded-3xl text-2xl font-black hover:bg-blue-500 transition-all shadow-2xl shadow-blue-600/40 uppercase tracking-widest text-white"
              >
                {user ? 'Start Creating' : 'Login to Start'}
              </button>
              <button 
                onClick={() => setShowHelpModal(true)}
                className="px-8 py-6 bg-white/5 border border-white/10 rounded-3xl text-lg font-bold hover:bg-white/10 transition-all text-gray-300 flex items-center justify-center gap-3"
              >
                <HelpCircle size={24} /> Learn More
              </button>
            </div>
          </div>
        )}

        {appState === AppState.GALLERY && user && (
          <GreetingGallery 
            greetings={myGreetings} 
            receivedGreetings={receivedGreetings}
            onDelete={handleDelete} 
            onEdit={handleEdit}
            onSelect={handleSelectGreeting}
            onCreateNew={handleNewScript}
          />
        )}

        {appState === AppState.IDLE && (
          <div className="w-full flex justify-center py-6">
            <GreetingCreator 
              onGenerate={handleGenerate} 
              onCancel={() => {
                setEditingGreeting(null);
                setAppState(user ? AppState.GALLERY : AppState.AUTH);
              }} 
              initialData={editingGreeting}
            />
          </div>
        )}

        {appState === AppState.LOADING && <LoadingIndicator />}

        {appState === AppState.SUCCESS && currentResult && (
          <GreetingResult 
            result={currentResult} 
            onRestart={handleNewScript} 
            onGoGallery={() => setAppState(user ? AppState.GALLERY : AppState.IDLE)}
            onInternalShare={handleInternalShare}
          />
        )}
      </main>

      <footer className="py-10 text-center text-gray-800 text-xs border-t border-white/5 w-full">
        <p className="font-bold tracking-widest uppercase">&copy; {new Date().getFullYear()} eGreetz &bull; Digital Production Studio</p>
      </footer>
    </div>
  );
};

export default App;

import {Video} from '@google/genai';

export enum AppState {
  IDLE,
  AUTH,
  LOADING,
  SUCCESS,
  ERROR,
  GALLERY
}

export enum Occasion {
  BIRTHDAY = 'Happy Birthday',
  CHRISTMAS = 'Merry Christmas',
  ANNIVERSARY = 'Happy Anniversary',
  NEW_YEARS = 'Happy New Years',
  PROMOTION = 'Congratulations on your Promotion',
  GRADUATION = 'Congratulations on your Graduation',
  CONGRATULATIONS = 'Congratulations',
  VALENTINES = 'Valentine\'s Day (Love & Romance)',
  EASTER = 'Happy Easter (Resurrection & Spring)',
  MOTHERS_DAY = 'Happy Mother\'s Day',
  FATHERS_DAY = 'Happy Father\'s Day',
  SYMPATHY = 'Deepest Sympathy (In Loving Memory)',
  THANK_YOU = 'Thank You'
}

export enum GreetingTheme {
  BALLOONS = 'Balloons dropping',
  CHAMPAGNE = 'Champagne popping',
  FIREWORKS = 'Fireworks',
  NOISE_MAKERS = 'Noise makers',
  HEARTS = 'Floating Hearts & Roses',
  FLOWERS = 'Blooming Spring Garden',
  CANDLES = 'Serene Candlelight',
  CONFETTI = 'Colorful Confetti',
  CLAPPING = 'Clapping and whistling',
  BOY_BABY_SHOWER = 'Boy Baby Shower',
  GIRL_BABY_SHOWER = 'Girl Baby Shower'
}

export enum VoiceGender {
  MALE_TENOR = 'Male (Tenor)',
  MALE_BASS = 'Male (Bass)',
  FEMALE = 'Female'
}

export enum VeoModel {
  VEO_FAST = 'veo-3.1-fast-generate-preview',
  VEO = 'veo-3.1-generate-preview',
}

export enum AspectRatio {
  LANDSCAPE = '16:9',
  PORTRAIT = '9:16',
}

export enum Resolution {
  P720 = '720p',
  P1080 = '1080p',
}

export enum GenerationMode {
  TEXT_TO_VIDEO = 'Text to Video',
  FRAMES_TO_VIDEO = 'Frames to Video',
  REFERENCES_TO_VIDEO = 'References to Video',
  EXTEND_VIDEO = 'Extend Video',
}

export interface ImageFile {
  file: File;
  base64: string;
}

export interface VideoFile {
  file: File;
  base64: string;
}

export interface GreetingRecord {
  id: string;
  userId: string;
  occasion: Occasion;
  message: string;
  theme: GreetingTheme;
  scenicDescription?: string;
  videoUrl: string;
  voice?: VoiceGender;
  createdAt: number;
}

export interface GenerateGreetingParams {
  occasion: Occasion;
  message: string;
  theme: GreetingTheme;
  scenicDescription?: string;
  voice: VoiceGender;
  userPhoto: ImageFile | null;
  model: VeoModel;
  aspectRatio: AspectRatio;
  extended: boolean;
}

export interface GenerateVideoParams {
  prompt: string;
  model: VeoModel;
  aspectRatio: AspectRatio;
  resolution: Resolution;
  mode: GenerationMode;
  startFrame: ImageFile | null;
  endFrame: ImageFile | null;
  referenceImages: ImageFile[];
  styleImage: ImageFile | null;
  inputVideo: VideoFile | null;
  inputVideoObject: Video | null;
  isLooping: boolean;
}

import React, { useState, useRef, useEffect } from 'react';
import { Occasion, GreetingTheme, VoiceGender, GenerateGreetingParams, ImageFile, VeoModel, AspectRatio, GreetingRecord } from '../types';
import { Mic, Upload, X, Sparkles, Wand2, ChevronLeft, Clock, Zap, HelpCircle, ChevronDown, Calendar, Wind, PenTool } from 'lucide-react';
import HelpModal from './HelpModal';

interface Props {
  onGenerate: (params: GenerateGreetingParams) => void;
  onCancel: () => void;
  initialData?: GreetingRecord | null;
}

const GreetingCreator: React.FC<Props> = ({ onGenerate, onCancel, initialData }) => {
  const [occasion, setOccasion] = useState<Occasion>(Occasion.BIRTHDAY);
  const [message, setMessage] = useState('');
  const [theme, setTheme] = useState<GreetingTheme>(GreetingTheme.BALLOONS);
  const [scenicDescription, setScenicDescription] = useState('');
  const [voice, setVoice] = useState<VoiceGender>(VoiceGender.FEMALE);
  const [photo, setPhoto] = useState<ImageFile | null>(null);
  const [isRecording, setIsRecording] = useState(false);
  const [extended, setExtended] = useState(false);
  const [showHelp, setShowHelp] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Sorting logic for enums to ensure alphabetical order A-Z
  const sortedOccasions = Object.values(Occasion).sort((a, b) => a.localeCompare(b));
  const sortedThemes = Object.values(GreetingTheme).sort((a, b) => a.localeCompare(b));

  // Initialize from initialData if editing
  useEffect(() => {
    if (initialData) {
      setOccasion(initialData.occasion);
      setMessage(initialData.message);
      setTheme(initialData.theme);
      if (initialData.scenicDescription) setScenicDescription(initialData.scenicDescription);
      if (initialData.voice) setVoice(initialData.voice);
    }
  }, [initialData]);

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = () => {
        setPhoto({ file, base64: (reader.result as string).split(',')[1] });
      };
      reader.readAsDataURL(file);
    }
  };

  const startSpeechRecognition = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitRecognition;
    if (!SpeechRecognition) {
      alert("Your browser doesn't support speech recognition.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'en-US';
    recognition.onstart = () => setIsRecording(true);
    recognition.onend = () => setIsRecording(false);
    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setMessage(prev => (prev + ' ' + transcript).trim());
    };
    recognition.start();
  };

  return (
    <div className="w-full max-w-4xl bg-black border border-white/10 rounded-3xl p-8 md:p-12 shadow-[0_0_100px_rgba(37,99,235,0.05)] animate-in fade-in slide-in-from-bottom-4 duration-700">
      <HelpModal isOpen={showHelp} onClose={() => setShowHelp(false)} />

      <div className="mb-10 flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div className="text-center md:text-left">
          <h2 className="text-4xl font-bold mb-2 flex items-center justify-center md:justify-start gap-3 text-white">
            <Sparkles className="text-blue-500 w-8 h-8" /> 
            {initialData ? 'Edit Masterpiece' : 'Cinematic Creator'}
            <button 
              onClick={() => setShowHelp(true)}
              className="p-2 text-gray-600 hover:text-blue-500 transition-colors"
              title="How to use"
            >
              <HelpCircle size={24} />
            </button>
          </h2>
          <p className="text-gray-400 text-lg">
            {initialData ? 'Refining your cinematic vision...' : 'Define your vision and let AI handle the production.'}
          </p>
        </div>
        <button 
          onClick={(e) => {
            e.preventDefault();
            onCancel();
          }}
          className="flex items-center justify-center gap-2 px-6 py-3 bg-white/5 border border-white/10 rounded-2xl text-gray-400 hover:text-white hover:bg-white/10 transition-all font-bold text-sm uppercase tracking-wider"
        >
          <ChevronLeft size={18} /> Cancel
        </button>
      </div>

      <div className="space-y-8">
        {/* SELECT OCCASION DROPDOWN */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="relative group">
            <label className="block text-xs font-bold text-gray-500 mb-3 uppercase tracking-[0.2em]">Select Occasion (A-Z)</label>
            <div className="relative">
              <div className="absolute inset-y-0 left-4 flex items-center pointer-events-none text-blue-500">
                <Calendar size={18} />
              </div>
              <select
                value={occasion}
                onChange={(e) => setOccasion(e.target.value as Occasion)}
                className="w-full bg-[#0a0a0c] border border-white/10 rounded-2xl pl-12 pr-10 py-4 text-white font-bold appearance-none cursor-pointer focus:outline-none focus:ring-2 focus:ring-blue-600 hover:bg-white/5 transition-all"
              >
                {sortedOccasions.map(occ => (
                  <option key={occ} value={occ} className="bg-[#0a0a0c] text-white py-2">
                    {occ}
                  </option>
                ))}
              </select>
              <div className="absolute inset-y-0 right-4 flex items-center pointer-events-none text-gray-500">
                <ChevronDown size={18} />
              </div>
            </div>
          </div>

          <div className="relative group">
            <label className="block text-xs font-bold text-gray-500 mb-3 uppercase tracking-[0.2em]">Atmospheric Environment (A-Z)</label>
            <div className="relative">
              <div className="absolute inset-y-0 left-4 flex items-center pointer-events-none text-blue-500">
                <Wind size={18} />
              </div>
              <select
                value={theme}
                onChange={(e) => setTheme(e.target.value as GreetingTheme)}
                className="w-full bg-[#0a0a0c] border border-white/10 rounded-2xl pl-12 pr-10 py-4 text-white font-bold appearance-none cursor-pointer focus:outline-none focus:ring-2 focus:ring-blue-600 hover:bg-white/5 transition-all"
              >
                {sortedThemes.map(t => (
                  <option key={t} value={t} className="bg-[#0a0a0c] text-white py-2">
                    {t}
                  </option>
                ))}
              </select>
              <div className="absolute inset-y-0 right-4 flex items-center pointer-events-none text-gray-500">
                <ChevronDown size={18} />
              </div>
            </div>
          </div>
        </div>

        {/* CUSTOM SCENIC DESCRIPTION */}
        <div>
          <label className="block text-xs font-bold text-gray-500 mb-3 uppercase tracking-[0.2em]">Scenic Description (Optional - Overrides Environment)</label>
          <div className="relative">
            <div className="absolute inset-y-0 left-4 flex items-center pointer-events-none text-blue-500">
              <PenTool size={18} />
            </div>
            <input
              type="text"
              value={scenicDescription}
              onChange={(e) => setScenicDescription(e.target.value)}
              placeholder="e.g. A futuristic city with holographic neon signs and rain..."
              className="w-full bg-[#0a0a0c] border border-white/10 rounded-2xl pl-12 pr-4 py-4 text-white font-medium focus:outline-none focus:ring-2 focus:ring-blue-600 hover:bg-white/5 transition-all placeholder-gray-700"
            />
          </div>
        </div>

        {/* YOUR MESSAGE */}
        <div>
          <div className="flex justify-between items-center mb-3">
            <label className="text-xs font-bold text-gray-500 uppercase tracking-[0.2em]">Greeting Script</label>
            <span className="text-[10px] font-black text-gray-600 uppercase tracking-widest">{message.length} / 1000</span>
          </div>
          <div className="relative">
            <textarea
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              placeholder="What would you like the video to say? AI will synchronize the speech for you..."
              className="w-full h-32 bg-[#0a0a0c] border border-white/5 rounded-3xl p-6 text-white text-lg placeholder-gray-700 focus:outline-none focus:ring-2 focus:ring-blue-600 transition-all resize-none shadow-inner"
              maxLength={1000}
            />
            <button
              onClick={startSpeechRecognition}
              className={`absolute bottom-4 right-4 p-3 rounded-full transition-all shadow-xl ${isRecording ? 'bg-red-500 animate-pulse text-white' : 'bg-blue-600 hover:bg-blue-500 text-white'}`}
              title="Voice to Text"
            >
              <Mic size={20} />
            </button>
          </div>
        </div>

        {/* Duration & Voice Modulation */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
           {/* Voice Modulation Dropdown */}
           <div className="relative group">
            <label className="block text-xs font-bold text-gray-500 mb-3 uppercase tracking-[0.2em]">Voice Modulation</label>
            <div className="relative">
              <select 
                value={voice}
                onChange={(e) => setVoice(e.target.value as VoiceGender)}
                className="w-full bg-[#0a0a0c] border border-white/10 rounded-2xl px-5 py-4 text-white font-bold appearance-none cursor-pointer focus:outline-none focus:ring-2 focus:ring-blue-600 hover:bg-white/5 transition-all"
              >
                {Object.values(VoiceGender).map(v => <option key={v} value={v} className="bg-[#0a0a0c] text-white">{v}</option>)}
              </select>
              <div className="absolute inset-y-0 right-4 flex items-center pointer-events-none text-gray-500">
                <ChevronDown size={18} />
              </div>
            </div>
          </div>

          <div className="p-4 bg-[#0a0a0c] border border-white/5 rounded-2xl flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className={`p-2 rounded-lg ${extended ? 'bg-blue-600 text-white' : 'bg-gray-800 text-gray-500'}`}>
                <Clock size={18} />
              </div>
              <div>
                <p className="font-black text-white uppercase tracking-widest text-[10px]">Director's Cut</p>
                <p className="text-gray-500 text-[10px]">Extend to 15 seconds</p>
              </div>
            </div>
            <button 
              onClick={() => setExtended(!extended)}
              className={`relative w-12 h-6 rounded-full transition-colors duration-300 ${extended ? 'bg-blue-600' : 'bg-gray-800'}`}
            >
              <div className={`absolute top-1 left-1 w-4 h-4 bg-white rounded-full transition-transform duration-300 ${extended ? 'translate-x-6' : ''}`} />
            </button>
          </div>
        </div>

        {/* Asset Upload */}
        <div className="relative group">
          <label className="block text-xs font-bold text-gray-500 mb-3 uppercase tracking-[0.2em]">Asset Reference (Optional)</label>
          {photo ? (
            <div className="relative w-full h-32 rounded-2xl overflow-hidden border border-white/5">
              <img src={URL.createObjectURL(photo.file)} alt="Preview" className="w-full h-full object-cover opacity-60" />
              <div className="absolute inset-0 flex items-center justify-center gap-4">
                <span className="text-xs font-black uppercase tracking-widest text-white drop-shadow-lg">Asset Ready</span>
                <button 
                  onClick={() => setPhoto(null)}
                  className="p-2 bg-red-600 rounded-full text-white hover:bg-red-500 transition-colors"
                >
                  <X size={16} />
                </button>
              </div>
            </div>
          ) : (
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="w-full h-20 bg-[#0a0a0c] border-2 border-dashed border-white/5 rounded-2xl flex items-center justify-center gap-4 text-gray-500 hover:text-blue-400 hover:bg-[#121214] transition-all"
            >
              <Upload size={24} className="opacity-30" />
              <span className="font-bold text-xs uppercase tracking-widest">Upload Character Reference</span>
            </button>
          )}
          <input ref={fileInputRef} type="file" className="hidden" accept="image/*" onChange={handlePhotoUpload} />
        </div>

        {/* Actions Section */}
        <div className="pt-4">
          <button
            onClick={() => onGenerate({ 
              occasion, 
              message, 
              theme, 
              scenicDescription,
              voice, 
              userPhoto: photo, 
              model: VeoModel.VEO_FAST, 
              aspectRatio: AspectRatio.LANDSCAPE,
              extended 
            })}
            disabled={!message.trim()}
