    while (currentProducedDuration < targetDuration) {
      console.log(`[Studio] Extending Production. Currently produced: ${currentProducedDuration}s. Final goal: ${targetDuration}s.`);

      /**
       * We add a deliberate delay to ensure the previous video URI is fully 
