/**
 * Generates a cinematic greeting video using Gemini Veo models.
 * Dynamically extends the production to match or exceed the audio script duration.
 * Ensures "Director's Cut" produces a significantly longer, high-production value video.
 */
export const generateGreetingVideo = async (
  params: GenerateGreetingParams & { audioDuration?: number }
): Promise<{ objectUrl: string; blob: Blob }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Calculate Target Duration
  // Video must be at least as long as the audio + a 5-second buffer for the final scene
  const audioDuration = params.audioDuration || 7;
  let targetDuration = Math.ceil(audioDuration) + 5; 

  // "Director's Cut" Enhancement:
  // User requested at least 15s. We target 25s (roughly 4 segments) to ensure 
  // a robust cinematic experience that definitely exceeds the 15s threshold.
  if (params.extended) {
    targetDuration = Math.max(targetDuration, 25);
  }

  const segmentLength = 7; // Veo standard segment length
  const needsExtension = targetDuration > segmentLength;

  /**
   * CRITICAL: Multi-segment video extension requires 'veo-3.1-generate-preview'
   * for consistent quality and backend state management.
   */
  const modelToUse = (needsExtension || params.userPhoto) 
    ? 'veo-3.1-generate-preview' 
    : params.model;

  const visualContext = params.scenicDescription && params.scenicDescription.trim().length > 0 
    ? `Visual Scene: ${params.scenicDescription}` 
    : `Visual Theme: ${params.theme}`;

  // Use the full script (up to 1000 chars) to guide the visual narrative across multiple segments
  const cinematicPrompt = `
    A cinematic, high-quality holiday greeting video for ${params.occasion}.
    ${visualContext}. 
    Atmosphere: Joyful, celebratory, professional cinematic lighting, 8k resolution feel.
    Visual storytelling guidance: The scene should evolve elegantly, showing various angles and celebratory details that match this message: ${params.message.substring(0, 1000)}
  `.trim();

  const config: any = {
    numberOfVideos: 1,
    resolution: '720p',
    aspectRatio: params.userPhoto ? '16:9' : params.aspectRatio,
  };

  const initialPayload: any = {
    model: modelToUse,
    prompt: cinematicPrompt,
    config: config,
  };

  if (params.userPhoto) {
    initialPayload.config.referenceImages = [{
      image: {
        imageBytes: params.userPhoto.base64,
        mimeType: params.userPhoto.file.type || 'image/jpeg',
      },
      referenceType: VideoGenerationReferenceType.ASSET,
    }];
  }

  try {
    console.log(`[Studio] Starting Full Scale Production. Audio: ${audioDuration.toFixed(1)}s. Target Video Length: ${targetDuration}s.`);

    // 1. Initial 7s Segment Generation
    let operation = await ai.models.generateVideos(initialPayload);
    while (!operation.done) {
      await new Promise((resolve) => setTimeout(resolve, 10000));
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }

    let currentVideoAsset = operation.response?.generatedVideos?.[0]?.video;
    if (!currentVideoAsset) throw new Error("Initial production failed to return video asset.");

    let currentProducedDuration = segmentLength;

    // 2. Iterative Extension Loop
    // We loop until the cumulative duration of the generated video segments reaches the goal.
    while (currentProducedDuration < targetDuration) {
      console.log(`[Studio] Extending Production. Currently at ${currentProducedDuration}s. Target: ${targetDuration}s.`);

      /**
       * BACKEND INDEXING DELAY:
       * We wait 20 seconds to ensure the previous video URI is fully processed 
       * by the Gemini backend and available as a seed for the extension call.
       */
      await new Promise((resolve) => setTimeout(resolve, 20000));

      const extensionPayload = {
        model: 'veo-3.1-generate-preview',
        prompt: `Continue the beautiful cinematic celebration for ${params.occasion}. Flow seamlessly from the previous visual, exploring more of the celebratory environment while maintaining perfect lighting and character consistency. More visual grandeur.`,
        video: currentVideoAsset,
        config: {
          numberOfVideos: 1,
          resolution: '720p',
          aspectRatio: config.aspectRatio,
        }
      };

      let extendOp = await ai.models.generateVideos(extensionPayload);
      while (!extendOp.done) {
        await new Promise((resolve) => setTimeout(resolve, 10000));
        extendOp = await ai.operations.getVideosOperation({ operation: extendOp });
      }

      const extendedAsset = extendOp.response?.generatedVideos?.[0]?.video;
      if (extendedAsset) {
        // Successfully extended the video chain
        currentVideoAsset = extendedAsset;
        currentProducedDuration += segmentLength;
      } else {
        console.warn("[Studio] Extension attempt failed to return a new asset. Finalizing production.");
        break; 
      }
    }

    const downloadLink = currentVideoAsset?.uri;
    if (downloadLink) {
      // Fetch the final merged MP4 bytes
      const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
      if (!response.ok) throw new Error('Failed to retrieve finalized production file.');

      const blob = await response.blob();
      console.log(`[Studio] Production Complete. Total length approx: ${currentProducedDuration}s.`);
      return { objectUrl: URL.createObjectURL(blob), blob };
    }
  } catch (error: any) {
    console.error("[Studio] Video Production Pipeline Failure:", error);
    throw error;
  }

  throw new Error('Video production pipeline failed to yield a final asset.');
};

/**
 * Generates audio for a greeting message using Gemini TTS.
 * Returns duration for video synchronization.
 */
export const generateGreetingVoice = async (text: string, voice: VoiceGender): Promise<{ base64: string, duration: number } | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const voiceMap: Record<VoiceGender, string> = {
    [VoiceGender.MALE_TENOR]: 'Kore',
    [VoiceGender.MALE_BASS]: 'Puck',
    [VoiceGender.FEMALE]: 'Charon'
  };

  try {
    // We provide the raw text directly to ensure the model doesn't summarize or truncate.
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: voiceMap[voice] },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) return null;

    const duration = await getAudioDuration(base64Audio);
    return { base64: base64Audio, duration };
  } catch (e) {
    console.error("Voice Generation failed:", e);
    return null;
  }
};

