    targetDuration = Math.max(targetDuration, 15);
  }

  const needsExtension = targetDuration > segmentLength;

  /**
   * CRITICAL: If any extension is required, the entire production chain 
   * MUST use 'veo-3.1-generate-preview' to ensure compatibility 
   * and avoid the 400 processing error.
   */
  const modelToUse = (needsExtension || params.userPhoto) 
    ? 'veo-3.1-generate-preview' 
    : 'veo-3.1-fast-generate-preview';

  // "None" Occasion logic: Use all words of the script for Awesome Cinematic Visuals
  const visualContext = params.scenicDescription && params.scenicDescription.trim().length > 0 
    ? `Visual Environment: ${params.scenicDescription}` 
    : (params.occasion !== Occasion.NONE ? `Visual Theme: ${params.theme}` : '');

  const occasionHeader = params.occasion !== Occasion.NONE 
    ? `Cinematic holiday greeting for ${params.occasion}` 
    : `Awesome Cinematic Masterpiece with conceptual narrative`;

  const scriptPriority = params.occasion === Occasion.NONE 
    ? `IMPORTANT: This video has no specific occasion. Use the ENTIRE script text below to create the Awesome Cinematic Visuals, interpreting the imagery, mood, and story directly from these words: "${params.message}"`
    : `Visual narrative based on this script: "${params.message.substring(0, 500)}..."`;

  const cinematicPrompt = `
    ${occasionHeader}.
    ${visualContext}. 
    Style: High-end professional cinematic lighting, 8k resolution textures, epic atmosphere, detailed textures.
    ${scriptPriority}
  `.trim();

  const config: any = {
    numberOfVideos: 1,
    resolution: '720p',
    aspectRatio: params.userPhoto ? '16:9' : params.aspectRatio,
  };

  const initialPayload: any = {
    model: modelToUse,
    prompt: cinematicPrompt,
    config: config,
  };

  if (params.userPhoto) {
    initialPayload.config.referenceImages = [{
      image: {
        imageBytes: params.userPhoto.base64,
        mimeType: params.userPhoto.file.type || 'image/jpeg',
      },
      referenceType: VideoGenerationReferenceType.ASSET,
    }];
  }

  try {
    console.log(`[Studio] Starting Production. Script Length: ${audioDuration.toFixed(1)}s. Target Video Length: ${targetDuration}s.`);

    // 2. Initial Segment Generation (0-7s)
    let operation = await ai.models.generateVideos(initialPayload);
    while (!operation.done) {
      await new Promise((resolve) => setTimeout(resolve, 10000));
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }

    let currentVideoAsset = operation.response?.generatedVideos?.[0]?.video;
    if (!currentVideoAsset) throw new Error("Initial production segment failed.");

    let currentProducedDuration = segmentLength;

    // 3. Iterative Extension Loop
    while (currentProducedDuration < targetDuration) {
      console.log(`[Studio] Extending Production. Progress: ${currentProducedDuration}s / ${targetDuration}s.`);

      /**
       * CRITICAL MITIGATION FOR 400 ERROR:
       * "Input video must be a video that was generated by VEO that has been processed."
       * This error indicates the video URI isn't ready for extension immediately after 'done'.
       * We increase wait time to 45 seconds to ensure indexing is complete.
       */
      console.log("[Studio] Waiting 45s for backend indexing...");
      await new Promise((resolve) => setTimeout(resolve, 45000));

      const extensionPayload = {
        model: 'veo-3.1-generate-preview',
        prompt: `Continue the cinematic visual narrative, flowing seamlessly from the previous shot. ${params.occasion === Occasion.NONE ? 'Further explore the visual world described in the script: ' + params.message.substring(0, 200) : 'Maintain lighting and character consistency for ' + params.occasion + '.'}`,
        video: currentVideoAsset,
        config: {
          numberOfVideos: 1,
          resolution: '720p',
          aspectRatio: config.aspectRatio,
        }
      };

      let extendOp = await ai.models.generateVideos(extensionPayload);
      while (!extendOp.done) {
        await new Promise((resolve) => setTimeout(resolve, 10000));
        extendOp = await ai.operations.getVideosOperation({ operation: extendOp });
      }

      const extendedAsset = extendOp.response?.generatedVideos?.[0]?.video;
      if (extendedAsset) {
        currentVideoAsset = extendedAsset;
        currentProducedDuration += segmentLength;
      } else {
        console.warn("[Studio] Extension attempt failed to return a new asset. Finalizing.");
        break; 
      }
    }

    const downloadLink = currentVideoAsset?.uri;
    if (downloadLink) {
      const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
      if (!response.ok) throw new Error('Failed to retrieve finalized production file.');

      const blob = await response.blob();
      console.log(`[Studio] Production Successful. Final length: ~${currentProducedDuration}s.`);
      return { objectUrl: URL.createObjectURL(blob), blob };
    }
  } catch (error: any) {
    console.error("[Studio] Video Production Failure:", error);
    throw error;
  }

  throw new Error('Video production pipeline failed.');
};

/**
 * Generates audio for a greeting message using Gemini TTS.
 * Returns duration for video synchronization.
 */
export const generateGreetingVoice = async (text: string, voice: VoiceGender): Promise<{ base64: string, duration: number } | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const voiceMap: Record<VoiceGender, string> = {
    [VoiceGender.MALE_TENOR]: 'Kore',
    [VoiceGender.MALE_BASS]: 'Puck',
    [VoiceGender.FEMALE]: 'Charon'
  };

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: voiceMap[voice] },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) return null;

    const duration = await getAudioDuration(base64Audio);
    return { base64: base64Audio, duration };
  } catch (e) {
    console.error("Voice Generation failed:", e);
    return null;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Occasion, GreetingTheme, VoiceGender, GenerateGreetingParams, ImageFile, AudioFile, VeoModel, AspectRatio, GreetingRecord } from '../types';
import { Mic, Upload, X, Sparkles, Wand2, ChevronLeft, Clock, Zap, HelpCircle, ChevronDown, Calendar, Wind, PenTool, Music } from 'lucide-react';
import HelpModal from './HelpModal';

interface Props {
  onGenerate: (params: GenerateGreetingParams) => void;
  onCancel: () => void;
  initialData?: GreetingRecord | null;
}

const GreetingCreator: React.FC<Props> = ({ onGenerate, onCancel, initialData }) => {
  const [occasion, setOccasion] = useState<Occasion>(Occasion.NONE);
  const [message, setMessage] = useState('');
  const [theme, setTheme] = useState<GreetingTheme>(GreetingTheme.BALLOONS);
  const [scenicDescription, setScenicDescription] = useState('');
  const [voice, setVoice] = useState<VoiceGender>(VoiceGender.FEMALE);
  const [photo, setPhoto] = useState<ImageFile | null>(null);
  const [audioFile, setAudioFile] = useState<AudioFile | null>(null);
  const [isRecording, setIsRecording] = useState(false);
  const [extended, setExtended] = useState(false);
  const [showHelp, setShowHelp] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const audioInputRef = useRef<HTMLInputElement>(null);

  // Sorting logic for enums: 'None' always first, then A-Z
  const sortedOccasions = [
    Occasion.NONE,
    ...Object.values(Occasion)
      .filter(o => o !== Occasion.NONE)
      .sort((a, b) => a.localeCompare(b))
  ];

  const sortedThemes = Object.values(GreetingTheme).sort((a, b) => a.localeCompare(b));

  // Initialize from initialData if editing
  useEffect(() => {
    if (initialData) {
      setOccasion(initialData.occasion);
      setMessage(initialData.message);
      setTheme(initialData.theme);
      if (initialData.scenicDescription) setScenicDescription(initialData.scenicDescription);
      if (initialData.voice) setVoice(initialData.voice);
    }
  }, [initialData]);

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = () => {
        setPhoto({ file, base64: (reader.result as string).split(',')[1] });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAudioUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = () => {
        setAudioFile({ file, base64: (reader.result as string).split(',')[1] });
      };
      reader.readAsDataURL(file);
    }
  };

  const startSpeechRecognition = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitRecognition;
    if (!SpeechRecognition) {
      alert("Your browser doesn't support speech recognition.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'en-US';
    recognition.onstart = () => setIsRecording(true);
    recognition.onend = () => setIsRecording(false);
    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setMessage(prev => (prev + ' ' + transcript).trim());
    };
    recognition.start();
  };

  return (
    <div className="w-full max-w-4xl bg-black border border-white/10 rounded-3xl p-8 md:p-12 shadow-[0_0_100px_rgba(37,99,235,0.05)] animate-in fade-in slide-in-from-bottom-4 duration-700">
      <HelpModal isOpen={showHelp} onClose={() => setShowHelp(false)} />

      <div className="mb-10 flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div className="text-center md:text-left">
