import {
  GoogleGenAI,
  Modality,
  VideoGenerationReferenceType,
} from '@google/genai';
import { GenerateGreetingParams, VoiceGender, VeoModel, Occasion } from '../types';

/**
 * Helper to decode base64 audio and get its duration in seconds.
 * Gemini TTS output is raw PCM at 24kHz 16-bit mono.
 */
async function getAudioDuration(base64Data: string): Promise<number> {
  try {
    const binaryString = atob(base64Data);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    // 2 bytes per sample (16-bit), 24000 samples per second
    const duration = (bytes.length / 2) / 24000; 
    return duration;
  } catch (e) {
    console.warn("[Studio] Could not determine audio duration accurately, defaulting to 10s", e);
    return 10;
  }
}

/**
 * Generates a cinematic greeting video using Gemini Veo models.
 * Dynamically extends the production to match or exceed the audio script duration.
 * Ensures "Director's Cut" produces a video of at least 15 seconds.
 */
export const generateGreetingVideo = async (
  params: GenerateGreetingParams & { audioDuration?: number }
): Promise<{ objectUrl: string; blob: Blob }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // 1. Calculate Target Duration
  const segmentLength = 7; // Veo standard segment length
  const audioDuration = params.audioDuration || 7;

  // Video must be slightly longer than the audio for a clean outro
  let targetDuration = Math.ceil(audioDuration) + 2; 

  // "Director's Cut" logic: Force a minimum of 15 seconds.
  if (params.extended) {
    targetDuration = Math.max(targetDuration, 15);
  }

  const needsExtension = targetDuration > segmentLength;

  /**
   * CRITICAL: If any extension is required, the entire production chain 
   * MUST use 'veo-3.1-generate-preview' to ensure compatibility 
   * with the extension endpoint.
   */
  const modelToUse = (needsExtension || params.userPhoto) 
    ? 'veo-3.1-generate-preview' 
    : 'veo-3.1-fast-generate-preview';

  // "None" Occasion logic: Focus entirely on the script for "Awesome Cinematic Visuals"
  const visualContext = params.scenicDescription && params.scenicDescription.trim().length > 0 
    ? `Visual World: ${params.scenicDescription}` 
    : (params.occasion !== Occasion.NONE ? `Visual Theme: ${params.theme}` : '');

  const occasionHeader = params.occasion !== Occasion.NONE 
    ? `Cinematic masterpiece for ${params.occasion}` 
    : `Epic Cinematic Narrative Video`;

  const visualInstruction = params.occasion === Occasion.NONE 
    ? `IMPORTANT: There is no specific occasion. Use the ENTIRE script text to create AWESOME CINEMATIC VISUALS. Interpret every keyword for imagery: "${params.message}"`
    : `Visual narrative context based on script: "${params.message.substring(0, 500)}"`;

  const cinematicPrompt = `
    ${occasionHeader}.
    ${visualContext}. 
    Style: Professional cinematic production, 8k resolution textures, dramatic lighting, epic scale.
    ${visualInstruction}
  `.trim();

  const config: any = {
    numberOfVideos: 1,
    resolution: '720p',
    aspectRatio: params.userPhoto ? '16:9' : params.aspectRatio,
  };

  const initialPayload: any = {
    model: modelToUse,
    prompt: cinematicPrompt,
    config: config,
  };

  if (params.userPhoto) {
    initialPayload.config.referenceImages = [{
      image: {
        imageBytes: params.userPhoto.base64,
        mimeType: params.userPhoto.file.type || 'image/jpeg',
      },
      referenceType: VideoGenerationReferenceType.ASSET,
    }];
  }

  try {
    console.log(`[Studio] Starting Production. Script: ${audioDuration.toFixed(1)}s. Target Video: ${targetDuration}s.`);

    // 2. Initial Segment (0-7s)
    let operation = await ai.models.generateVideos(initialPayload);
    while (!operation.done) {
      await new Promise((resolve) => setTimeout(resolve, 10000));
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }

    let currentVideoAsset = operation.response?.generatedVideos?.[0]?.video;
    if (!currentVideoAsset) throw new Error("Initial production segment failed.");

    let currentProducedDuration = segmentLength;

    // 3. Iterative Extension Loop
    while (currentProducedDuration < targetDuration) {
      console.log(`[Studio] Extending Production. Progress: ${currentProducedDuration}s / ${targetDuration}s.`);

      /**
       * Delay for backend processing to avoid "video must be processed" 400 error.
       */
      await new Promise((resolve) => setTimeout(resolve, 45000));

      const extensionPayload = {
        model: 'veo-3.1-generate-preview',
        prompt: `Continue this awesome cinematic narrative seamlessly. Follow the story and mood established by the script: ${params.message.substring(0, 200)}...`,
        video: currentVideoAsset,
        config: {
          numberOfVideos: 1,
          resolution: '720p',
          aspectRatio: config.aspectRatio,
        }
      };

      let extendOp = await ai.models.generateVideos(extensionPayload);
      while (!extendOp.done) {
        await new Promise((resolve) => setTimeout(resolve, 10000));
        extendOp = await ai.operations.getVideosOperation({ operation: extendOp });
      }

      const extendedAsset = extendOp.response?.generatedVideos?.[0]?.video;
      if (extendedAsset) {
        currentVideoAsset = extendedAsset;
        currentProducedDuration += segmentLength;
      } else {
        break; 
      }
    }

    const downloadLink = currentVideoAsset?.uri;
    if (downloadLink) {
      const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
      if (!response.ok) throw new Error('Failed to retrieve finalized production file.');

      const blob = await response.blob();
      return { objectUrl: URL.createObjectURL(blob), blob };
    }
  } catch (error: any) {
    console.error("[Studio] Production Pipeline Failure:", error);
    throw error;
  }

  throw new Error('Production pipeline failed.');
};

/**
 * Generates audio for a greeting message using Gemini TTS.
 * Returns duration and blobs for synchronization and persistent storage.
 */
export const generateGreetingVoice = async (text: string, voice: VoiceGender): Promise<{ base64: string, duration: number, blob: Blob } | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const voiceMap: Record<VoiceGender, string> = {
    [VoiceGender.MALE_TENOR]: 'Kore',
    [VoiceGender.MALE_BASS]: 'Puck',
    [VoiceGender.FEMALE]: 'Charon'
  };

  try {
    // Improved prompt to prevent "repeating voice" bug
    const ttsPrompt = `Read the following script exactly once, in a natural cinematic tone, without any repetitions or phrases playing back more than once. Read only the words provided. Script: "${text}"`;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: ttsPrompt }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: voiceMap[voice] },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) return null;

    const duration = await getAudioDuration(base64Audio);

    // Create Blob for persistent storage
    const binaryString = atob(base64Audio);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    const blob = new Blob([bytes], { type: 'audio/pcm' });

    return { base64: base64Audio, duration, blob };
  } catch (e) {
    console.error("Voice Generation failed:", e);
    return null;
  }
};

import React, { useState, useEffect } from 'react';
import { 
  loginWithGoogle, 
  logout, 
  getUserGreetings, 
  saveGreeting, 
  updateGreeting,
  deleteGreeting, 
  isFirebaseEnabled, 
  onAuthStateChangedListener,
  uploadVideoToCloud,
  uploadAudioToCloud,
  getReceivedGreetings,
  sendToInternalUser,
  type User 
} from './services/firebase';
import { AppState, GenerateGreetingParams, GreetingRecord, VeoModel, AspectRatio, VoiceGender } from './types';
import GreetingCreator from './components/GreetingCreator';
import GreetingGallery from './components/GreetingGallery';
import GreetingResult from './components/GreetingResult';
import LoadingIndicator from './components/LoadingIndicator';
import ApiKeyDialog from './components/ApiKeyDialog';
import HelpModal from './components/HelpModal';
import { LogIn, LogOut, Plus, ShieldCheck, Key, AlertCircle, HelpCircle, RefreshCw } from 'lucide-react';
import { generateGreetingVideo, generateGreetingVoice } from './services/geminiService';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [appState, setAppState] = useState<AppState>(AppState.AUTH);
  const [myGreetings, setMyGreetings] = useState<GreetingRecord[]>([]);
  const [receivedGreetings, setReceivedGreetings] = useState<GreetingRecord[]>([]);
  const [currentResult, setCurrentResult] = useState<{ url: string; params: GenerateGreetingParams; record?: GreetingRecord; audioUrl?: string; voiceUrl?: string; backgroundMusicUrl?: string } | null>(null);
  const [editingGreeting, setEditingGreeting] = useState<GreetingRecord | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [showApiKeyDialog, setShowApiKeyDialog] = useState(false);
  const [showHelpModal, setShowHelpModal] = useState(false);
  const [isKeyConnected, setIsKeyConnected] = useState(false);
  const [isFirebaseReady, setIsFirebaseReady] = useState(false);

  useEffect(() => {
    const init = async () => {
      setIsFirebaseReady(isFirebaseEnabled());

      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setIsKeyConnected(hasKey);
      } else {
        const key = process.env.API_KEY;
        setIsKeyConnected(!!key);
      }
    };

    init();

    const unsubscribe = onAuthStateChangedListener((u) => {
      setUser(u);
      if (u) {
        loadData(u);
        if (appState === AppState.AUTH) {
          setAppState(AppState.GALLERY);
        }
      } else {
        setAppState(AppState.AUTH);
      }
    });

    return () => {
      if (typeof unsubscribe === 'function') unsubscribe();
    };
  }, [appState]);

  const loadData = async (u: User) => {
    try {
      const [mine, received] = await Promise.all([
        getUserGreetings(u.uid),
        u.email ? getReceivedGreetings(u.email) : Promise.resolve([])
      ]);
      setMyGreetings(mine);
      setReceivedGreetings(received);
    } catch (err) {
      console.error("Failed to load user data:", err);
    }
  };

  const handleRefresh = () => {
    if (user) {
      loadData(user);
    }
  };

  const handleGenerate = async (params: GenerateGreetingParams) => {
    if (!user) {
      alert("Please login with your Google Account to create and share cinematic greetings.");
      setAppState(AppState.AUTH);
      return;
    }

    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        setShowApiKeyDialog(true);
        return;
      }
    }

    setIsLoading(true);
    setAppState(AppState.LOADING);

    try {
      // 1. Generate Voice (TTS)
      const voiceResult = await generateGreetingVoice(params.message, params.voice);
      const audioDuration = voiceResult?.duration || 7;
      const audioBase64 = voiceResult?.base64;
      const voiceBlob = voiceResult?.blob;

      // 2. Generate Cinematic Video (Extended logic handled inside geminiService)
      const { blob } = await generateGreetingVideo({ 
        ...params, 
        audioDuration 
      });

      let finalUrl = "";
      let backgroundMusicUrl = "";
      let voiceUrl = "";
      let newRecord: GreetingRecord | undefined;

      if (isFirebaseReady) {
        // Parallel upload for speed
        const uploads: Promise<string>[] = [
          uploadVideoToCloud(blob, user.uid)
        ];

        // Add voice synthesized audio to cloud storage
        if (voiceBlob) {
          uploads.push(uploadAudioToCloud(voiceBlob, user.uid));
        }

        // Add custom music if selected
        if (params.backgroundMusic) {
          uploads.push(uploadAudioToCloud(params.backgroundMusic.file, user.uid));
        }

        const results = await Promise.all(uploads);
        finalUrl = results[0];

        let idx = 1;
        if (voiceBlob) {
          voiceUrl = results[idx++];
        }
        if (params.backgroundMusic) {
          backgroundMusicUrl = results[idx++];
        } else {
          backgroundMusicUrl = editingGreeting?.backgroundMusicUrl || "";
        }

        if (editingGreeting) {
          await updateGreeting(editingGreeting.id, {
            occasion: params.occasion,
            message: params.message,
            theme: params.theme,
            scenicDescription: params.scenicDescription,
            videoUrl: finalUrl,
            voice: params.voice,
            voiceUrl: voiceUrl,
            backgroundMusicUrl: backgroundMusicUrl
          });

          newRecord = {
            ...editingGreeting,
            occasion: params.occasion,
            message: params.message,
            theme: params.theme,
            scenicDescription: params.scenicDescription,
            videoUrl: finalUrl,
            voice: params.voice,
            voiceUrl: voiceUrl,
            backgroundMusicUrl: backgroundMusicUrl
          };
        } else {
          const docRef = await saveGreeting(user.uid, {
            userId: user.uid,
            occasion: params.occasion,
            message: params.message,
            theme: params.theme,
            scenicDescription: params.scenicDescription,
            videoUrl: finalUrl,
            voice: params.voice,
            voiceUrl: voiceUrl,
            backgroundMusicUrl: backgroundMusicUrl,
            createdAt: Date.now()
          });

          newRecord = {
            id: docRef.id,
            userId: user.uid,
            occasion: params.occasion,
            message: params.message,
            theme: params.theme,
            scenicDescription: params.scenicDescription,
            videoUrl: finalUrl,
            voice: params.voice,
            voiceUrl: voiceUrl,
            backgroundMusicUrl: backgroundMusicUrl,
            createdAt: Date.now()
          };
        }

        setEditingGreeting(null);
        loadData(user);
      } else {
        finalUrl = URL.createObjectURL(blob);
        backgroundMusicUrl = params.backgroundMusic ? URL.createObjectURL(params.backgroundMusic.file) : "";
      }

      setCurrentResult({ 
        url: finalUrl, 
        params, 
        record: newRecord,
        audioUrl: audioBase64,
        voiceUrl: voiceUrl,
        backgroundMusicUrl: backgroundMusicUrl
      });
      setAppState(AppState.SUCCESS);
    } catch (e: any) {
      console.error("Production Error:", e);
      alert("Production Error: " + e.toString());
      setAppState(user ? AppState.GALLERY : AppState.IDLE);
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (window.confirm("Permanently delete this cinematic greeting?")) {
      try {
        await deleteGreeting(id);
        if (user) loadData(user);
      } catch (error) {
        console.error("Deletion failed:", error);
      }
    }
  };

  const handleEdit = (greeting: GreetingRecord) => {
    setEditingGreeting(greeting);
    setAppState(AppState.IDLE);
  };

  const handleSelectGreeting = (greeting: GreetingRecord) => {
    setCurrentResult({
      url: greeting.videoUrl,
      record: greeting,
      voiceUrl: greeting.voiceUrl,
      backgroundMusicUrl: greeting.backgroundMusicUrl,
      params: {
        occasion: greeting.occasion,
        message: greeting.message,
        theme: greeting.theme,
        scenicDescription: greeting.scenicDescription,
        voice: greeting.voice || VoiceGender.FEMALE, 
        userPhoto: null,
        backgroundMusic: null,
        model: VeoModel.VEO_FAST,
        aspectRatio: AspectRatio.LANDSCAPE,
        extended: false
      }
    });
    setAppState(AppState.SUCCESS);
  };

  const handleInternalShare = async (email: string) => {
    if (!currentResult?.record || !user) return;
    try {
      await sendToInternalUser(user.displayName || "A Friend", email, currentResult.record);
      alert("Sent! This greeting will appear in their library shortly.");
    } catch (err: any) {
      alert("Internal share failed: " + err.message);
    }
  };

  const handleNewScript = () => {
    setEditingGreeting(null);
    setAppState(AppState.IDLE);
  };

  return (
    <div className="min-h-screen bg-black text-white flex flex-col font-sans selection:bg-blue-600/30">
      {showApiKeyDialog && <ApiKeyDialog onContinue={() => {
        if (window.aistudio) {
          window.aistudio.openSelectKey();
          setIsKeyConnected(true);
          setShowApiKeyDialog(false);
        }
      }} />}

      <HelpModal isOpen={showHelpModal} onClose={() => setShowHelpModal(false)} />

      <header className="px-6 py-5 flex justify-between items-center border-b border-white/5 bg-black/95 backdrop-blur-xl sticky top-0 z-50">
        <div 
          className="flex items-center gap-2 cursor-pointer group" 
          onClick={() => setAppState(user ? AppState.GALLERY : AppState.AUTH)}
        >
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center font-bold text-xl shadow-[0_0_20px_rgba(37,99,235,0.4)] group-hover:scale-105 transition-transform text-white">
            eG
          </div>
          <div className="flex flex-col">
            <h1 className="text-2xl font-black tracking-tight text-white leading-none">eGreetz</h1>
            <div className="flex items-center gap-1.5 mt-1.5">
              <span className={`flex h-2 w-2 rounded-full ${isKeyConnected ? 'bg-green-500' : 'bg-yellow-500 animate-pulse'}`}></span>
              <span className="text-[10px] text-gray-400 font-black tracking-widest uppercase">
                {isKeyConnected ? 'Studio Ready' : 'Connect Key'}
              </span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-4">
          {user && (
            <button 
              onClick={handleRefresh}
              className="p-2 text-gray-400 hover:text-white transition-colors"
              title="Refresh Library"
            >
              <RefreshCw size={20} className={isLoading ? 'animate-spin' : ''} />
            </button>
          )}
          <button 
            onClick={() => setShowHelpModal(true)}
            className="p-2 text-gray-400 hover:text-white transition-colors"
            title="Help & Info"
          >
            <HelpCircle size={22} />
          </button>
          {user ? (
            <>
