export interface ImageFile {
  file: File;
  base64: string;
}

export interface AudioFile {
  file: File;
  base64: string;
}

export interface VideoFile {
  file: File;
  base64: string;
}

export interface GreetingRecord {
  id: string;
  userId: string;
  occasion: Occasion;
  message: string;
  theme: GreetingTheme;
