}

export interface GenerateGreetingParams {
  occasion: Occasion;
  message: string;
  theme: GreetingTheme;
  scenicDescription?: string;
  voice: VoiceGender;
  userPhoto: ImageFile | null;
  scenePhoto: ImageFile | null;
  backgroundMusic: AudioFile | null;
  model: VeoModel;
  aspectRatio: AspectRatio;
  extended: boolean;
}

