import {
  GoogleGenAI,
  Modality,
  VideoGenerationReferenceType,
} from '@google/genai';
import { GenerateGreetingParams, VoiceGender, VeoModel, Occasion, GreetingTheme } from '../types';

/**
 * Helper to decode base64 audio and get its duration in seconds.
 */
async function getAudioDuration(base64Data: string): Promise<number> {
  try {
    const binaryString = atob(base64Data);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    // PCM 16bit 24kHz Mono is 2 bytes per sample
    const duration = (bytes.length / 2) / 24000; 
    return duration;
  } catch (e) {
    return 10;
  }
}

/**
 * Robust polling for Veo operations with a retry mechanism for transient API errors.
 */
async function pollOperation(ai: any, initialOp: any, maxRetries = 3): Promise<any> {
  let operation = initialOp;
  let retryCount = 0;

  while (!operation.done) {
    try {
      await new Promise((resolve) => setTimeout(resolve, 8000));
      operation = await ai.operations.getVideosOperation({ operation: operation });

      if (operation.error) {
        // Handle transient 500s or "Internal Server Issue"
        const isTransient = operation.error.code === 500 || 
                          operation.error.message?.toLowerCase().includes("internal server issue") ||
                          operation.error.message?.toLowerCase().includes("transient");

        if (isTransient && retryCount < maxRetries) {
          console.warn(`[Studio] Transient API error in operation. Retrying poll... (${retryCount + 1}/${maxRetries})`);
          retryCount++;
          continue; 
        }
        throw new Error(operation.error.message);
      }
    } catch (e: any) {
      if (retryCount < maxRetries) {
        retryCount++;
        await new Promise(r => setTimeout(r, 2000));
        continue;
      }
      throw e;
    }
  }
  return operation;
}

/**
 * Generates a cinematic greeting video with phonetic lip-sync and enforced silence.
 */
export const generateGreetingVideo = async (
  params: GenerateGreetingParams & { audioDuration?: number }
): Promise<{ objectUrl: string; blob: Blob }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const segmentLength = 7;
  const audioDuration = params.audioDuration || 7;
  // Visual buffer to ensure speech isn't cut off by video end
  let targetDuration = Math.ceil(audioDuration) + 4.0; 

  if (params.extended) {
    targetDuration = Math.max(targetDuration, 15);
  }

  const hasReferences = !!(params.userPhoto || params.scenePhoto);

  // Use the full quality model by default for high reliability in cinematic productions
  const modelToUse = 'veo-3.1-generate-preview';

  const effectiveTheme = params.theme === GreetingTheme.NONE ? "" : params.theme;
  const environment = params.scenicDescription || effectiveTheme || "Cinematic Studio";

  const baseCinematicInstruction = `
    MASTER PRODUCTION: High-end ${params.occasion !== Occasion.NONE ? params.occasion : 'Cinematic Masterpiece'}.
    ENVIRONMENT: ${environment}. 
    STYLE: Professional 8k cinematography, realistic lighting, detailed textures.
    CRITICAL: THE VIDEO FILE MUST BE COMPLETELY SILENT. NO AUDIO TRACKS.
  `.trim();

  const lipSyncInstruction = params.userPhoto 
    ? `CHARACTER PERFORMANCE: The person in the reference image is speaking directly to the lens. LIP-SYNC: Sync their mouth and jaw movements perfectly with this script: "${params.message}". Narrate the FULL script.`
    : `VISUAL RESPONSE: The camera and environment move cinematically to the rhythm of the spoken message: "${params.message}".`;

  const initialPayload: any = {
    model: modelToUse,
    prompt: `${baseCinematicInstruction}\n${lipSyncInstruction}`,
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: '16:9',
    },
  };

  const referenceImages: any[] = [];
  if (params.userPhoto) {
    referenceImages.push({
      image: { imageBytes: params.userPhoto.base64, mimeType: params.userPhoto.file.type || 'image/jpeg' },
      referenceType: VideoGenerationReferenceType.ASSET,
    });
  }
  if (params.scenePhoto) {
    referenceImages.push({
      image: { imageBytes: params.scenePhoto.base64, mimeType: params.scenePhoto.file.type || 'image/jpeg' },
      referenceType: VideoGenerationReferenceType.ASSET,
    });
  }
  if (referenceImages.length > 0) {
    initialPayload.config.referenceImages = referenceImages;
  }

  try {
    // Attempt initial generation with process-level retry
    let operation;
    let attempts = 0;
    const maxAttempts = 2;

    while (attempts < maxAttempts) {
      try {
        operation = await ai.models.generateVideos(initialPayload);
        operation = await pollOperation(ai, operation);

        if (operation.response?.generatedVideos?.[0]?.video) break;

        attempts++;
        if (attempts < maxAttempts) console.warn("[Studio] Initial segment returned no asset. Retrying full request...");
      } catch (e) {
        attempts++;
        if (attempts >= maxAttempts) throw e;
        await new Promise(r => setTimeout(r, 3000));
      }
    }

    let currentVideoAsset = operation?.response?.generatedVideos?.[0]?.video;
    if (!currentVideoAsset) {
      throw new Error("Video Production Failed: The model did not return a video asset. This may be due to safety filters or persistent internal server issues.");
    }

    let currentProducedDuration = segmentLength;

    // Extension Loop: Match visual timeline to audio narration
    while (currentProducedDuration < targetDuration) {
      const extensionPrompt = `
        Continue the cinematic shot with absolute visual continuity.
        LIP-SYNC: Maintain the performance for the remaining narration: "${params.message}".
        Identical lighting, focus, and character presence.
        CRITICAL: THE VIDEO MUST REMAIN SILENT.
      `.trim();

      const extensionPayload = {
        model: 'veo-3.1-generate-preview',
        prompt: extensionPrompt,
        video: currentVideoAsset,
        config: {
          numberOfVideos: 1,
          resolution: '720p',
          aspectRatio: '16:9',
        }
      };

      try {
        let extendOp = await ai.models.generateVideos(extensionPayload);
        extendOp = await pollOperation(ai, extendOp);

        const extendedAsset = extendOp.response?.generatedVideos?.[0]?.video;
        if (extendedAsset) {
          currentVideoAsset = extendedAsset;
          currentProducedDuration += segmentLength;
        } else {
          console.warn("[Studio] Extension segment empty, finishing with partial video.");
          break; 
        }
      } catch (extError: any) {
        console.error("[Studio] Extension Segment Failed:", extError);
        // Fallback: return what we have so far instead of failing completely
        if (currentVideoAsset) break;
        throw extError;
      }
    }

    const downloadLink = currentVideoAsset?.uri;
    if (downloadLink) {
      const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
      if (!response.ok) throw new Error("Failed to download video from production server.");
      const blob = await response.blob();
      return { objectUrl: URL.createObjectURL(blob), blob };
    }
  } catch (error: any) {
    console.error("[Studio] Pipeline Failure:", error);
    throw error;
  }
  throw new Error('Production pipeline critical failure.');
};

/**
 * Generates high-fidelity audio for a greeting message.
 */
export const generateGreetingVoice = async (params: GenerateGreetingParams): Promise<{ base64: string, duration: number, blob: Blob } | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const voiceMap: Record<VoiceGender, string> = {
    [VoiceGender.MALE_TENOR]: 'Kore',
    [VoiceGender.MALE_BASS]: 'Puck',
    [VoiceGender.FEMALE]: 'Charon'
  };

  try {
    const effectiveTheme = params.theme === GreetingTheme.NONE ? "" : params.theme;
    const environment = params.scenicDescription || effectiveTheme || "Cinematic Studio";

    // AGGRESSIVE ANTI-MODERATOR COMMANDS
    const voicePersona = `
      NARRATOR COMMAND: You are a professional, high-end Human Cinematic Actor. 
      STYLE: Your performance is warm, rich, emotive, and 100% human. 
      FORBIDDEN: You MUST NOT sound like a "Moderator", "AI Assistant", "Robotic Voice", or "Virtual Help Desk". 
      PERFORMANCE CONTEXT: You are narrating a personal greeting in a high-fidelity ${environment} acoustic space. 
      MANDATORY: Speak every single word of the script clearly and cinematically. Do NOT shorten.
    `.trim();

    const ttsPrompt = `
      ${voicePersona}
      ACTUAL SCRIPT: "${params.message}"
    `.trim();

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: ttsPrompt }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: voiceMap[params.voice] },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) return null;

    const duration = await getAudioDuration(base64Audio);

    const binaryString = atob(base64Audio);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    const blob = new Blob([bytes], { type: 'audio/pcm' });

    return { base64: base64Audio, duration, blob };
  } catch (e) {
    console.error("[Studio] Voice Generation Error:", e);
    throw e;
  }
};

