    }

    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        setShowApiKeyDialog(true);
        return;
      }
    }

    setIsLoading(true);
    setAppState(AppState.LOADING);

    try {
      // Voice generation is removed as requested
      const { blob } = await generateGreetingVideo(params);

      let videoUrl = "";
      let musicUrl = "";
      let newRecord: GreetingRecord | undefined;

      if (isFirebaseReady) {
        const uploads: Promise<string>[] = [
          uploadVideoToCloud(blob, user.uid)
        ];

        if (params.backgroundMusic) {
          uploads.push(uploadAudioToCloud(params.backgroundMusic.file, user.uid));
        }

        const results = await Promise.all(uploads);
        videoUrl = results[0];

        if (params.backgroundMusic) {
          musicUrl = results[1];
        } else {
          musicUrl = editingGreeting?.backgroundMusicUrl || "";
        }

        const recordData = {
          occasion: params.occasion,
          message: params.message,
          theme: params.theme,
          scenicDescription: params.scenicDescription,
          videoUrl: videoUrl,
          voice: params.voice,
          voiceUrl: "", // No longer used
          backgroundMusicUrl: musicUrl
        };

        if (editingGreeting) {
          await updateGreeting(editingGreeting.id, recordData);
          newRecord = { ...editingGreeting, ...recordData };
        } else {
          const docRef = await saveGreeting(user.uid, {
            ...recordData,
            userId: user.uid,
            createdAt: Date.now()
          });
          newRecord = { id: docRef.id, userId: user.uid, ...recordData, createdAt: Date.now() };
        }
        loadData(user);
      } else {
        videoUrl = URL.createObjectURL(blob);
        musicUrl = params.backgroundMusic ? URL.createObjectURL(params.backgroundMusic.file) : "";
      }

      setCurrentResult({ 
        url: videoUrl, 
        params, 
        record: newRecord,
        backgroundMusicUrl: musicUrl
      });
      setAppState(AppState.SUCCESS);
    } catch (e: any) {
      console.error("Production Error:", e);
      if (e.message?.includes("API Key") || e.message?.includes("not found")) {
        alert("Session or API key expired. Please re-select your Paid API Key.");
        if (window.aistudio) {
          setIsKeyConnected(false);
          setShowApiKeyDialog(true);
        }
      } else {
        alert("Production Error: " + e.message);
      }
      setAppState(user ? AppState.GALLERY : AppState.IDLE);
    } finally {
      setIsLoading(false);
    }
  };

  const handleEdit = (greeting: GreetingRecord) => {
    setEditingGreeting(greeting);
    setAppState(AppState.IDLE);
  };

  const handleSelectGreeting = (greeting: GreetingRecord) => {
    setCurrentResult({
      url: greeting.videoUrl,
      record: greeting,
      backgroundMusicUrl: greeting.backgroundMusicUrl,
      params: {
        occasion: greeting.occasion,
        message: greeting.message,
        theme: greeting.theme,
        scenicDescription: greeting.scenicDescription,
        voice: greeting.voice || VoiceGender.FEMALE, 
        userPhoto: null,
        scenePhoto: null,
        backgroundMusic: null,
        model: VeoModel.VEO_FAST,
        aspectRatio: AspectRatio.LANDSCAPE,
        extended: false
      }
    });
    setAppState(AppState.SUCCESS);
  };

  if (isAuthInitializing) {
    return (
      <div className="min-h-screen bg-black flex items-center justify-center">
        <div className="w-12 h-12 border-4 border-t-transparent border-blue-600 rounded-full animate-spin"></div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-black text-white flex flex-col font-sans selection:bg-blue-600/30">
      {showApiKeyDialog && <ApiKeyDialog onContinue={() => {
        if (window.aistudio) {
          window.aistudio.openSelectKey();
          setIsKeyConnected(true);
          setShowApiKeyDialog(false);
        }
      }} />}

      <HelpModal isOpen={showHelpModal} onClose={() => setShowHelpModal(false)} />

      <header className="px-6 py-5 flex justify-between items-center border-b border-white/5 bg-black/95 backdrop-blur-xl sticky top-0 z-50">
        <div 
          className="flex items-center gap-2 cursor-pointer group" 
          onClick={() => setAppState(user ? AppState.GALLERY : AppState.AUTH)}
        >
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center font-bold text-xl shadow-[0_0_20px_rgba(37,99,235,0.4)] group-hover:scale-105 transition-transform text-white">eG</div>
          <div className="flex flex-col">
            <h1 className="text-2xl font-black tracking-tight text-white leading-none">eGreetz</h1>
            <div className="flex items-center gap-1.5 mt-1.5">
              <span className={`flex h-2 w-2 rounded-full ${isKeyConnected ? 'bg-green-500' : 'bg-yellow-500 animate-pulse'}`}></span>
              <span className="text-[10px] text-gray-400 font-black tracking-widest uppercase">{isKeyConnected ? 'Studio Ready' : 'Connect Key'}</span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-4">
          {user && (
            <button onClick={handleRefresh} className="p-2 text-gray-400 hover:text-white transition-colors">
              <RefreshCw size={20} className={isLoading ? 'animate-spin' : ''} />
            </button>
          )}
          <button onClick={() => setShowHelpModal(true)} className="p-2 text-gray-400 hover:text-white transition-colors">
            <HelpCircle size={22} />
          </button>
          {user ? (
            <>
              <button onClick={() => { setEditingGreeting(null); setAppState(AppState.IDLE); }} className="flex items-center gap-2 px-6 py-2 bg-blue-600 rounded-full hover:bg-blue-500 transition-all font-bold text-sm text-white">
                <Plus size={16} strokeWidth={3} /> New Script
              </button>
              <button onClick={logout} className="p-2 text-gray-500 hover:text-white transition-colors"><LogOut size={20} /></button>
            </>
          ) : (
            <button onClick={loginWithGoogle} className="flex items-center gap-2 px-7 py-2.5 bg-white text-black font-black rounded-full hover:bg-gray-200 transition-all text-sm uppercase tracking-wider">
              <LogIn size={16} strokeWidth={3} /> Login
            </button>
          )}
        </div>
      </header>

      <main className="flex-grow flex flex-col items-center p-6 w-full max-w-6xl mx-auto">
        {!isFirebaseReady && (
          <div className="w-full max-w-4xl mb-6 p-4 bg-red-900/10 border border-red-500/20 rounded-2xl flex items-center gap-3 text-red-200 text-sm">
            <AlertCircle size={20} className="text-red-400" />
            <span>Cloud Sync Inactive. Sharing is limited.</span>
          </div>
        )}

        {appState === AppState.AUTH && (
          <div className="flex-grow flex flex-col items-center justify-center text-center max-w-3xl animate-in fade-in zoom-in duration-1000 mt-20">
            <h2 className="text-7xl font-black mb-8 leading-[1] text-white tracking-tighter">Cinematic <span className="text-blue-600">Reimagined.</span></h2>
            <p className="text-2xl text-gray-400 mb-12 leading-relaxed font-medium">Create Hollywood-grade greetings. Personal persistent storage for your cinematic legacy.</p>
            <button onClick={user ? () => setAppState(AppState.IDLE) : loginWithGoogle} className="px-16 py-6 bg-blue-600 rounded-3xl text-2xl font-black hover:bg-blue-500 transition-all shadow-2xl shadow-blue-600/40 uppercase tracking-widest text-white">
              {user ? 'Start Creating' : 'Login to Start'}
            </button>
          </div>
        )}

        {appState === AppState.GALLERY && user && (
          <div className="w-full h-full flex flex-col">
            <GreetingGallery 
              greetings={myGreetings} 
              receivedGreetings={receivedGreetings}
              onDelete={async (id) => { if(window.confirm("Delete?")) { await deleteGreeting(id); loadData(user); } }} 
              onEdit={handleEdit}
              onSelect={handleSelectGreeting}
              onCreateNew={() => { setEditingGreeting(null); setAppState(AppState.IDLE); }}
            />
          </div>
        )}

        {appState === AppState.IDLE && (
          <div className="w-full flex justify-center py-6">
            <GreetingCreator 
              onGenerate={handleGenerate} 
              onCancel={() => setAppState(user ? AppState.GALLERY : AppState.AUTH)} 
              initialData={editingGreeting}
            />
          </div>
        )}

        {appState === AppState.LOADING && <LoadingIndicator />}

        {appState === AppState.SUCCESS && currentResult && (
          <GreetingResult 
            result={currentResult} 
            onRestart={() => { setEditingGreeting(null); setAppState(AppState.IDLE); }} 
            onGoGallery={() => setAppState(AppState.GALLERY)}
            onInternalShare={async (email) => { 
              if(currentResult.record) {
                await sendToInternalUser(user?.displayName || "Friend", email, currentResult.record);
                alert("Shared!");
              }
            }}
          />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Occasion, GreetingTheme, VoiceGender, GenerateGreetingParams, ImageFile, AudioFile, VeoModel, AspectRatio, GreetingRecord } from '../types';
import { Mic, Upload, X, Sparkles, ChevronLeft, Clock, Zap, HelpCircle, ChevronDown, Calendar, Wind, PenTool, Music, Image as ImageIcon } from 'lucide-react';
import HelpModal from './HelpModal';

interface Props {
  onGenerate: (params: GenerateGreetingParams) => void;
  onCancel: () => void;
  initialData?: GreetingRecord | null;
}

const GreetingCreator: React.FC<Props> = ({ onGenerate, onCancel, initialData }) => {
  const [occasion, setOccasion] = useState<Occasion>(Occasion.NONE);
  const [message, setMessage] = useState('');
  const [theme, setTheme] = useState<GreetingTheme>(GreetingTheme.NONE);
  const [scenicDescription, setScenicDescription] = useState('');
  const [photo, setPhoto] = useState<ImageFile | null>(null);
  const [scenePhoto, setScenePhoto] = useState<ImageFile | null>(null);
  const [audioFile, setAudioFile] = useState<AudioFile | null>(null);
  const [isRecording, setIsRecording] = useState(false);
  const [extended, setExtended] = useState(false);
  const [showHelp, setShowHelp] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const sceneInputRef = useRef<HTMLInputElement>(null);
  const audioInputRef = useRef<HTMLInputElement>(null);

  const sortedOccasions = [
    Occasion.NONE,
    ...Object.values(Occasion)
      .filter(o => o !== Occasion.NONE)
      .sort((a, b) => a.localeCompare(b))
  ];

  const sortedThemes = [
    GreetingTheme.NONE,
    ...Object.values(GreetingTheme)
      .filter(t => t !== GreetingTheme.NONE)
      .sort((a, b) => a.localeCompare(b))
  ];

  useEffect(() => {
    if (initialData) {
      setOccasion(initialData.occasion);
      setMessage(initialData.message);
      setTheme(initialData.theme);
      if (initialData.scenicDescription) setScenicDescription(initialData.scenicDescription);
    }
  }, [initialData]);

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = () => {
        setPhoto({ file, base64: (reader.result as string).split(',')[1] });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSceneUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = () => {
        setScenePhoto({ file, base64: (reader.result as string).split(',')[1] });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAudioUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = () => {
        setAudioFile({ file, base64: (reader.result as string).split(',')[1] });
      };
      reader.readAsDataURL(file);
    }
  };

  const startSpeechRecognition = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitRecognition;
    if (!SpeechRecognition) {
      alert("Your browser doesn't support speech recognition.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'en-US';
    recognition.onstart = () => setIsRecording(true);
    recognition.onend = () => setIsRecording(false);
    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setMessage(prev => (prev + ' ' + transcript).trim());
    };
    recognition.start();
  };

  return (
    <div className="w-full max-w-4xl bg-black border border-white/10 rounded-3xl p-8 md:p-12 shadow-[0_0_100px_rgba(37,99,235,0.05)] animate-in fade-in slide-in-from-bottom-4 duration-700">
      <HelpModal isOpen={showHelp} onClose={() => setShowHelp(false)} />

      <div className="mb-10 flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div className="text-center md:text-left">
          <h2 className="text-4xl font-bold mb-2 flex items-center justify-center md:justify-start gap-3 text-white">
            <Sparkles className="text-blue-500 w-8 h-8" /> 
            {initialData ? 'Edit Masterpiece' : 'Cinematic Creator'}
            <button 
              onClick={() => setShowHelp(true)}
              className="p-2 text-gray-600 hover:text-blue-500 transition-colors"
              title="How to use"
            >
              <HelpCircle size={24} />
            </button>
          </h2>
          <p className="text-gray-400 text-lg">
            {initialData ? 'Refining your cinematic vision...' : 'Define your vision and let AI handle the production.'}
          </p>
        </div>
        <button 
          onClick={(e) => {
            e.preventDefault();
            onCancel();
          }}
          className="flex items-center justify-center gap-2 px-6 py-3 bg-white/5 border border-white/10 rounded-2xl text-gray-400 hover:text-white hover:bg-white/10 transition-all font-bold text-sm uppercase tracking-wider"
        >
          <ChevronLeft size={18} /> Cancel
        </button>
      </div>

      <div className="space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="relative group">
            <label className="block text-xs font-bold text-gray-500 mb-3 uppercase tracking-[0.2em]">Select Occasion</label>
            <div className="relative">
              <div className="absolute inset-y-0 left-4 flex items-center pointer-events-none text-blue-500">
                <Calendar size={18} />
              </div>
              <select
                value={occasion}
                onChange={(e) => setOccasion(e.target.value as Occasion)}
                className="w-full bg-[#0a0a0c] border border-white/10 rounded-2xl pl-12 pr-10 py-4 text-white font-bold appearance-none cursor-pointer focus:outline-none focus:ring-2 focus:ring-blue-600 hover:bg-white/5 transition-all"
              >
                {sortedOccasions.map(occ => (
                  <option key={occ} value={occ} className="bg-[#0a0a0c] text-white py-2">
                    {occ}
                  </option>
                ))}
              </select>
              <div className="absolute inset-y-0 right-4 flex items-center pointer-events-none text-gray-500">
                <ChevronDown size={18} />
              </div>
            </div>
          </div>

          <div className="relative group">
            <label className="block text-xs font-bold text-gray-500 mb-3 uppercase tracking-[0.2em]">Atmospheric Environment</label>
            <div className="relative">
              <div className="absolute inset-y-0 left-4 flex items-center pointer-events-none text-blue-500">
                <Wind size={18} />
              </div>
              <select
                value={theme}
                onChange={(e) => setTheme(e.target.value as GreetingTheme)}
                className="w-full bg-[#0a0a0c] border border-white/10 rounded-2xl pl-12 pr-10 py-4 text-white font-bold appearance-none cursor-pointer focus:outline-none focus:ring-2 focus:ring-blue-600 hover:bg-white/5 transition-all"
              >
                {sortedThemes.map(t => (
                  <option key={t} value={t} className="bg-[#0a0a0c] text-white py-2">
                    {t}
                  </option>
                ))}
              </select>
              <div className="absolute inset-y-0 right-4 flex items-center pointer-events-none text-gray-500">
                <ChevronDown size={18} />
              </div>
            </div>
          </div>
        </div>

        <div>
          <label className="block text-xs font-bold text-gray-500 mb-3 uppercase tracking-[0.2em]">Scenic Description & Visual Reference</label>
          <div className="flex flex-col md:flex-row gap-4">
            <div className="relative flex-grow">
              <div className="absolute inset-y-0 left-4 flex items-center pointer-events-none text-blue-500">
                <PenTool size={18} />
              </div>
              <input
                type="text"
                value={scenicDescription}
                onChange={(e) => setScenicDescription(e.target.value)}
                placeholder="Describe the background or upload a scene photo..."
                className="w-full bg-[#0a0a0c] border border-white/10 rounded-2xl pl-12 pr-4 py-4 text-white font-medium focus:outline-none focus:ring-2 focus:ring-blue-600 hover:bg-white/5 transition-all placeholder-gray-700 h-full"
              />
            </div>

            <div className="shrink-0">
              {scenePhoto ? (
                <div className="relative w-32 h-14 rounded-2xl overflow-hidden border border-white/10 bg-[#0a0a0c]">
                  <img src={URL.createObjectURL(scenePhoto.file)} alt="Scene" className="w-full h-full object-cover opacity-60" />
                  <button 
                    onClick={() => setScenePhoto(null)}
                    className="absolute inset-0 flex items-center justify-center bg-black/40 hover:bg-black/60 transition-colors text-white"
                  >
                    <X size={16} />
                  </button>
                </div>
              ) : (
                <button 
                  onClick={() => sceneInputRef.current?.click()}
                  className="w-32 h-14 bg-[#0a0a0c] border-2 border-dashed border-white/5 rounded-2xl flex flex-col items-center justify-center gap-1 text-gray-500 hover:text-blue-400 hover:bg-[#121214] transition-all"
                >
                  <ImageIcon size={18} className="opacity-30" />
                  <span className="font-bold text-[8px] uppercase tracking-widest">Scene Ref</span>
                </button>
              )}
              <input ref={sceneInputRef} type="file" className="hidden" accept="image/*" onChange={handleSceneUpload} />
            </div>
          </div>
        </div>

        <div>
          <div className="flex justify-between items-center mb-3">
            <label className="text-xs font-bold text-gray-500 uppercase tracking-[0.2em]">Greeting Script (Subtitles)</label>
            <span className="text-[10px] font-black text-gray-600 uppercase tracking-widest">{message.length} / 1000</span>
          </div>
          <div className="relative">
            <textarea
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              placeholder="Type your message here. It will be displayed as cinematic subtitles..."
              className="w-full h-32 bg-[#0a0a0c] border border-white/5 rounded-3xl p-6 text-white text-lg placeholder-gray-700 focus:outline-none focus:ring-2 focus:ring-blue-600 transition-all resize-none shadow-inner"
              maxLength={1000}
            />
            <button
              onClick={startSpeechRecognition}
              className={`absolute bottom-4 right-4 p-3 rounded-full transition-all shadow-xl ${isRecording ? 'bg-red-500 animate-pulse text-white' : 'bg-blue-600 hover:bg-blue-500 text-white'}`}
              title="Voice to Text"
            >
              <Mic size={20} />
            </button>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="relative group">
            <label className="block text-xs font-bold text-gray-500 mb-3 uppercase tracking-[0.2em]">Style Reference (Optional)</label>
            {photo ? (
              <div className="relative w-full h-24 rounded-2xl overflow-hidden border border-white/10 bg-[#0a0a0c]">
                <img src={URL.createObjectURL(photo.file)} alt="Preview" className="w-full h-full object-cover opacity-60" />
                <div className="absolute inset-0 flex items-center justify-center gap-4">
                  <span className="text-[10px] font-black uppercase tracking-widest text-white drop-shadow-lg">Asset Ready</span>
                  <button 
                    onClick={() => setPhoto(null)}
                    className="p-2 bg-red-600 rounded-full text-white hover:bg-red-500 transition-colors"
                  >
                    <X size={14} />
                  </button>
                </div>
              </div>
            ) : (
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="w-full h-24 bg-[#0a0a0c] border-2 border-dashed border-white/5 rounded-2xl flex flex-col items-center justify-center gap-2 text-gray-500 hover:text-blue-400 hover:bg-[#121214] transition-all"
              >
                <Upload size={20} className="opacity-30" />
                <span className="font-bold text-[10px] uppercase tracking-widest">Atmosphere Photo</span>
              </button>
            )}
            <input ref={fileInputRef} type="file" className="hidden" accept="image/*" onChange={handlePhotoUpload} />
          </div>

          <div className="relative group">
            <label className="block text-xs font-bold text-gray-500 mb-3 uppercase tracking-[0.2em]">Background Music (Optional)</label>
            {audioFile ? (
              <div className="relative w-full h-24 rounded-2xl overflow-hidden border border-white/10 bg-blue-600/5 flex items-center justify-center px-4">
                <div className="flex flex-col items-center">
                  <Music size={20} className="text-blue-500 mb-1" />
                  <span className="text-[10px] font-black uppercase tracking-widest text-blue-400 truncate max-w-full">{audioFile.file.name}</span>
                </div>
                <button 
                  onClick={() => setAudioFile(null)}
                  className="absolute top-2 right-2 p-1.5 bg-red-600 rounded-full text-white hover:bg-red-500 transition-colors"
                >
                  <X size={12} />
                </button>
              </div>
            ) : (
              <button 
                onClick={() => audioInputRef.current?.click()}
                className="w-full h-24 bg-[#0a0a0c] border-2 border-dashed border-white/5 rounded-2xl flex flex-col items-center justify-center gap-2 text-gray-500 hover:text-blue-400 hover:bg-[#121214] transition-all text-center px-4"
              >
                <Music size={20} className="opacity-30" />
                <span className="font-bold text-[10px] uppercase tracking-widest">Upload Audio</span>
              </button>
            )}
            <input 
              ref={audioInputRef} 
              type="file" 
              className="hidden" 
              accept=".mp3,.m4a,audio/*" 
              onChange={handleAudioUpload} 
            />
          </div>
        </div>

        <div className="flex justify-center">
          <div className="p-6 bg-[#0a0a0c] border border-white/5 rounded-3xl flex items-center justify-between w-full max-w-md">
            <div className="flex items-center gap-3">
              <div className={`p-2 rounded-lg ${extended ? 'bg-blue-600 text-white' : 'bg-gray-800 text-gray-500'}`}>
                <Clock size={18} />
              </div>
              <div>
                <p className="font-black text-white uppercase tracking-widest text-[10px]">Director's Cut</p>
                <p className="text-gray-500 text-[10px]">14s+ Extended Production</p>
              </div>
            </div>
            <button 
              onClick={() => setExtended(!extended)}
              className={`relative w-12 h-6 rounded-full transition-colors duration-300 ${extended ? 'bg-blue-600' : 'bg-gray-800'}`}
            >
              <div className={`absolute top-1 left-1 w-4 h-4 bg-white rounded-full transition-transform duration-300 ${extended ? 'translate-x-6' : ''}`} />
            </button>
          </div>
        </div>

        <div className="pt-4">
          <button
            onClick={() => onGenerate({ 
              occasion, 
              message, 
              theme, 
              scenicDescription,
              voice: VoiceGender.FEMALE, // Defaulted, not used in UI
              userPhoto: photo, 
              scenePhoto,
              backgroundMusic: audioFile,
              model: VeoModel.VEO_FAST, 
              aspectRatio: AspectRatio.LANDSCAPE,
              extended 
            })}
            disabled={!message.trim()}
            className="w-full py-6 bg-blue-600 rounded-3xl font-black text-2xl flex items-center justify-center gap-5 hover:bg-blue-500 transition-all active:scale-[0.99] disabled:opacity-30 disabled:cursor-not-allowed shadow-[0_20px_60px_-15px_rgba(37,99,235,0.6)] text-white"
          >
            <Zap size={28} fill="currentColor" /> {initialData ? 'Update & Generate' : `Produce Full Production`}
          </button>
        </div>
      </div>
    </div>
  );
};

export default GreetingCreator;

import React, { useState, useRef, useEffect } from 'react';
import { GenerateGreetingParams, GreetingRecord } from '../types';
import { RefreshCw, LayoutGrid, Globe, Volume2, Share, Users, Type } from 'lucide-react';

interface Props {
  result: { 
    url: string; 
    params: GenerateGreetingParams; 
    record?: GreetingRecord; 
    audioUrl?: string; 
    voiceUrl?: string; 
    backgroundMusicUrl?: string 
  };
  onRestart: () => void;
  onGoGallery: () => void;
  onInternalShare?: (email: string) => void;
}

const GreetingResult: React.FC<Props> = ({ result, onRestart, onGoGallery, onInternalShare }) => {
  const [copied, setCopied] = useState(false);
  const [canNativeShare, setCanNativeShare] = useState(false);
  const [showCaptions, setShowCaptions] = useState(true);
  const videoRef = useRef<HTMLVideoElement>(null);

  const audioContextRef = useRef<AudioContext | null>(null);
  const musicBufferRef = useRef<AudioBuffer | null>(null);
  const musicNodeRef = useRef<AudioBufferSourceNode | null>(null);

  const shareUrl = result.url;
  const isCloudLink = shareUrl.startsWith('http');

  useEffect(() => {
    if (navigator.share && navigator.canShare) {
      const shareData = { title: 'eGreetz', text: 'Cinematic Greeting!', url: shareUrl };
      setCanNativeShare(navigator.canShare(shareData));
    }

    if ('mediaSession' in navigator) {
      navigator.mediaSession.metadata = new MediaMetadata({
        title: result.params.occasion || 'Cinematic Greeting',
        artist: 'eGreetz AI Production',
        album: 'High-Fidelity Greetings',
      });
    }
  }, [shareUrl, result.params.occasion]);

  // Background Music Loading
  useEffect(() => {
    const initAudio = async () => {
      try {
        const ctx = new (window.AudioContext || (window as any).webkitAudioContext)({
          latencyHint: 'playback'
        });
        audioContextRef.current = ctx;

        // Load Background Track
        const musicSource = result.backgroundMusicUrl || 'https://actions.google.com/static/audio/tracks/Epic_Cinematic_Saga.mp3';
        const musicResp = await fetch(musicSource);
        const musicArrayBuffer = await musicResp.arrayBuffer();
        musicBufferRef.current = await ctx.decodeAudioData(musicArrayBuffer);
      } catch (err) {
        console.error("[Studio] Audio Initialization Failure:", err);
      }
    };

    initAudio();
    return () => {
      if (audioContextRef.current) {
        audioContextRef.current.close();
        audioContextRef.current = null;
      }
    };
  }, [result.backgroundMusicUrl]);

  // Sync Music with Video Playback
  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;

    const stopAudio = () => {
      if (musicNodeRef.current) {
        try { musicNodeRef.current.stop(); } catch (e) {}
        musicNodeRef.current = null;
      }
    };

    const playAudio = async (offset: number) => {
      stopAudio();
      const ctx = audioContextRef.current;
      if (!ctx || ctx.state === 'closed') return;

      if (ctx.state === 'suspended') await ctx.resume();

      // Background Music
      if (musicBufferRef.current) {
        const mSrc = ctx.createBufferSource();
        mSrc.buffer = musicBufferRef.current;
        mSrc.loop = true;
        const mGain = ctx.createGain();
        mGain.gain.value = 0.25;
        mGain.connect(ctx.destination);
        mSrc.connect(mGain);
        mSrc.start(0, offset % musicBufferRef.current.duration);
        musicNodeRef.current = mSrc;
      }
    };

    const onPlay = () => playAudio(video.currentTime);
    const onPause = () => stopAudio();
    const onSeek = () => { if (!video.paused) playAudio(video.currentTime); };

    video.addEventListener('play', onPlay);
    video.addEventListener('pause', onPause);
    video.addEventListener('seeked', onSeek);

    return () => {
      video.removeEventListener('play', onPlay);
      video.removeEventListener('pause', onPause);
      video.removeEventListener('seeked', onSeek);
      stopAudio();
    };
  }, []);

  const handleCopy = () => {
    navigator.clipboard.writeText(shareUrl);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="w-full max-w-4xl animate-in zoom-in duration-500">
      <div className="text-center mb-10">
        <h2 className="text-5xl font-black mb-4 tracking-tighter text-white uppercase italic">Production Wrapped</h2>
        <p className="text-gray-400 font-medium italic opacity-60">"{result.params.message.substring(0, 80)}..."</p>
      </div>

      <div className="relative group rounded-3xl overflow-hidden shadow-2xl shadow-blue-500/20 mb-8 aspect-video bg-black ring-1 ring-white/10">
        <video 
          ref={videoRef}
          src={result.url} 
          controls 
          autoPlay 
          loop 
          muted 
          playsInline
          crossOrigin="anonymous"
          className="w-full h-full object-contain"
        />

        {showCaptions && (
          <div className="absolute bottom-16 left-0 right-0 px-10 flex justify-center pointer-events-none">
            <div className="bg-black/60 backdrop-blur-xl px-10 py-5 rounded-3xl text-white text-center text-xl font-black border border-white/20 shadow-2xl max-w-[90%] leading-relaxed tracking-tight">
              {result.params.message}
            </div>
          </div>
        )}

        <div className="absolute top-4 right-4 flex flex-col gap-2 items-end">
          <div className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest text-white backdrop-blur-md ${isCloudLink ? 'bg-blue-600/80' : 'bg-yellow-600/80'}`}>
            {isCloudLink ? <><Globe size={12} /> Cloud Master</> : <><Volume2 size={12} /> Local Production</>}
          </div>
          <button 
            onClick={() => setShowCaptions(!showCaptions)}
            className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest text-white backdrop-blur-md transition-all ${showCaptions ? 'bg-blue-600 shadow-lg' : 'bg-gray-800/80 hover:bg-gray-700'}`}
          >
            <Type size={12} /> {showCaptions ? 'Captions ON' : 'Captions OFF'}
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="bg-[#111114] border border-white/10 rounded-3xl p-8">
          <h3 className="text-xl font-black mb-6 flex items-center gap-3 text-white">Share Masterpiece</h3>
          <div className="grid grid-cols-2 gap-4">
            {canNativeShare && (
              <button onClick={() => navigator.share({url: shareUrl})} className="col-span-2 flex items-center justify-center gap-3 p-5 bg-blue-600 text-white hover:bg-blue-500 rounded-2xl transition-all font-black text-sm uppercase tracking-widest">
                <Share size={20} /> App Share
              </button>
            )}
            <button onClick={handleCopy} className="flex items-center justify-center gap-3 p-4 bg-white/5 hover:bg-white/10 rounded-2xl border border-white/5 font-bold text-sm text-gray-300">
              {copied ? <Globe size={18} className="text-green-500" /> : <Globe size={18} />} {copied ? 'Copied' : 'Copy Link'}
            </button>
            <button onClick={() => {
              const email = prompt("Recipient Google Email:");
              if (email && onInternalShare) onInternalShare(email.trim());
            }} className="flex items-center justify-center gap-3 p-4 bg-blue-600/10 text-blue-400 border border-blue-500/20 rounded-2xl font-bold text-sm hover:bg-blue-600/20">
              <Users size={18} /> Direct Send
            </button>
          </div>
        </div>
        <div className="flex flex-col gap-4 justify-center">
          <button onClick={onRestart} className="w-full py-5 bg-blue-600 text-white font-black rounded-3xl flex items-center justify-center gap-3 hover:bg-blue-500 transition-all text-lg uppercase tracking-wider shadow-2xl shadow-blue-600/20">
            <RefreshCw size={22} /> New Masterpiece
          </button>
          <button onClick={onGoGallery} className="w-full py-5 bg-white/5 border border-white/10 font-black rounded-3xl flex items-center justify-center gap-3 hover:bg-white/10 transition-all text-gray-400 hover:text-white uppercase tracking-wider">
            <LayoutGrid size={22} /> View Library
          </button>
        </div>
      </div>
    </div>
  );
};

export default GreetingResult;

import {
  GoogleGenAI,
  Modality,
  VideoGenerationReferenceType,
} from '@google/genai';
import { GenerateGreetingParams, VeoModel, Occasion, GreetingTheme, VoiceGender } from '../types';

/**
 * Helper to decode base64 audio and get its duration in seconds.
 */
async function getAudioDuration(base64Data: string): Promise<number> {
  try {
    const binaryString = atob(base64Data);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    // PCM 16bit 24kHz Mono is 2 bytes per sample
    const duration = (bytes.length / 2) / 24000; 
    return duration;
  } catch (e) {
    return 10;
  }
}

/**
 * Generates a cinematic greeting video focusing on atmosphere and occasion.
 */
export const generateGreetingVideo = async (
  params: GenerateGreetingParams
): Promise<{ objectUrl: string; blob: Blob }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const segmentLength = 7;
  const targetDuration = params.extended ? 14 : 7;

  const hasReferences = !!(params.userPhoto || params.scenePhoto);

  const runGeneration = async (modelOverride?: VeoModel) => {
    const modelToUse = modelOverride || (hasReferences 
      ? 'veo-3.1-generate-preview' 
      : 'veo-3.1-fast-generate-preview');

    const effectiveTheme = params.theme === GreetingTheme.NONE ? "" : params.theme;
    const environment = params.scenicDescription || effectiveTheme || "Cinematic Studio";

    const prompt = `
      CINEMATIC PRODUCTION: A high-quality visual atmosphere for a ${params.occasion !== Occasion.NONE ? params.occasion : 'special celebration'}.
      ENVIRONMENT: ${environment}. 
      VISUAL STYLE: Professional 8k cinematography, cinematic lighting, elegant camera movements.
      MOOD: The video should capture the essence of ${params.occasion} and the beauty of ${environment}.
      TECHNICAL: Silent video output.
    `.trim();

    const payload: any = {
      model: modelToUse,
      prompt: prompt,
      config: {
        numberOfVideos: 1,
        resolution: '720p',
        aspectRatio: '16:9',
      },
    };

    const referenceImages: any[] = [];
    if (params.userPhoto) {
      referenceImages.push({
        image: { imageBytes: params.userPhoto.base64, mimeType: params.userPhoto.file.type || 'image/jpeg' },
        referenceType: VideoGenerationReferenceType.ASSET,
      });
    }
    if (params.scenePhoto) {
      referenceImages.push({
        image: { imageBytes: params.scenePhoto.base64, mimeType: params.scenePhoto.file.type || 'image/jpeg' },
        referenceType: VideoGenerationReferenceType.ASSET,
      });
    }
    if (referenceImages.length > 0) {
      payload.config.referenceImages = referenceImages;
    }

    let operation = await ai.models.generateVideos(payload);

    while (!operation.done) {
      await new Promise((resolve) => setTimeout(resolve, 10000));
      operation = await ai.operations.getVideosOperation({ operation: operation });
      if (operation.error) {
        throw new Error(operation.error.message);
      }
    }

    const videoAsset = operation.response?.generatedVideos?.[0]?.video;
    if (!videoAsset) {
      throw new Error("EMPTY_RESULT");
    }

    return videoAsset;
  };

  try {
    let currentVideoAsset;
    try {
      currentVideoAsset = await runGeneration();
    } catch (e: any) {
      console.warn("[Gemini] First attempt failed, retrying with stable model...");
      currentVideoAsset = await runGeneration(VeoModel.VEO);
    }

    let currentProducedDuration = segmentLength;

    while (currentProducedDuration < targetDuration) {
      try {
        const extensionPayload = {
          model: 'veo-3.1-generate-preview',
          prompt: `Seamlessly continue the cinematic shot with matching lighting and atmosphere for ${params.occasion}.`,
          video: currentVideoAsset,
          config: {
            numberOfVideos: 1,
            resolution: '720p',
            aspectRatio: '16:9',
          }
        };

        let extendOp = await ai.models.generateVideos(extensionPayload);
        while (!extendOp.done) {
          await new Promise((resolve) => setTimeout(resolve, 10000));
          extendOp = await ai.operations.getVideosOperation({ operation: extendOp });
          if (extendOp.error) break; 
        }

        const extendedAsset = extendOp.response?.generatedVideos?.[0]?.video;
        if (extendedAsset) {
          currentVideoAsset = extendedAsset;
          currentProducedDuration += segmentLength;
        } else {
          break; 
        }
      } catch (extError) {
        break;
      }
    }

    const downloadLink = currentVideoAsset?.uri;
    if (downloadLink) {
      const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
      if (!response.ok) throw new Error("Failed to download video asset.");
      const blob = await response.blob();
      return { objectUrl: URL.createObjectURL(blob), blob };
    }
  } catch (error: any) {
    console.error("[Gemini] Production Pipeline Failure:", error);
    throw new Error(error.message === "EMPTY_RESULT" ? "Model generation error. Try simplifying your description." : error.message);
  }
  throw new Error('Video production pipeline failure.');
};

/**
 * Generates high-fidelity audio for a greeting message.
 */
export const generateGreetingVoice = async (params: GenerateGreetingParams): Promise<{ base64: string, duration: number, blob: Blob } | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const voiceMap: Record<VoiceGender, string> = {
    [VoiceGender.MALE_TENOR]: 'Kore',
    [VoiceGender.MALE_BASS]: 'Puck',
    [VoiceGender.FEMALE]: 'Charon'
  };

  try {
    const ttsPrompt = `
      You are a professional human narrator with a warm, natural, and expressive voice.
      Please narrate the following message with heartfelt emotion, speaking every word clearly:
      "${params.message}"
    `.trim();

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: ttsPrompt }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: voiceMap[params.voice] },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) return null;

    const duration = await getAudioDuration(base64Audio);

    const binaryString = atob(base64Audio);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    const blob = new Blob([bytes], { type: 'audio/pcm' });

    return { base64: base64Audio, duration, blob };
  } catch (e) {
    console.error("[Gemini] Voice Generation failed:", e);
    return null;
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { 
  loginWithGoogle, 
  logout, 
  getUserGreetings, 
  saveGreeting, 
  updateGreeting,
  deleteGreeting, 
  isFirebaseEnabled, 
  onAuthStateChangedListener,
  uploadVideoToCloud,
  uploadAudioToCloud,
  getReceivedGreetings,
  sendToInternalUser,
  type User 
} from './services/firebase';
import { AppState, GenerateGreetingParams, GreetingRecord, VeoModel, AspectRatio, VoiceGender } from './types';
import GreetingCreator from './components/GreetingCreator';
import GreetingGallery from './components/GreetingGallery';
import GreetingResult from './components/GreetingResult';
import LoadingIndicator from './components/LoadingIndicator';
import ApiKeyDialog from './components/ApiKeyDialog';
import HelpModal from './components/HelpModal';
import { LogIn, LogOut, Plus, HelpCircle, RefreshCw, AlertCircle } from 'lucide-react';
import { generateGreetingVideo, generateGreetingVoice } from './services/geminiService';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [appState, setAppState] = useState<AppState>(AppState.AUTH);
  const [myGreetings, setMyGreetings] = useState<GreetingRecord[]>([]);
  const [receivedGreetings, setReceivedGreetings] = useState<GreetingRecord[]>([]);
  const [currentResult, setCurrentResult] = useState<{ 
    url: string; 
    params: GenerateGreetingParams; 
    record?: GreetingRecord; 
    audioUrl?: string; 
    voiceUrl?: string; 
    backgroundMusicUrl?: string 
  } | null>(null);
  const [editingGreeting, setEditingGreeting] = useState<GreetingRecord | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isAuthInitializing, setIsAuthInitializing] = useState(true);
  const [showApiKeyDialog, setShowApiKeyDialog] = useState(false);
  const [showHelpModal, setShowHelpModal] = useState(false);
  const [isKeyConnected, setIsKeyConnected] = useState(false);
  const [isFirebaseReady, setIsFirebaseReady] = useState(false);

  const loadData = useCallback(async (u: User) => {
    try {
      const [mine, received] = await Promise.all([
        getUserGreetings(u.uid),
        u.email ? getReceivedGreetings(u.email) : Promise.resolve([])
      ]);
      setMyGreetings(mine);
      setReceivedGreetings(received);
    } catch (err) {
      console.error("Failed to load user data:", err);
    }
  }, []);

  useEffect(() => {
    const init = async () => {
      setIsFirebaseReady(isFirebaseEnabled());

      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setIsKeyConnected(hasKey);
      } else {
        const key = process.env.API_KEY;
        setIsKeyConnected(!!key);
      }
    };

    init();

    const unsubscribe = onAuthStateChangedListener((u) => {
      setUser(u);
      setIsAuthInitializing(false);
      if (u) {
        loadData(u);
        setAppState(AppState.GALLERY);
      } else {
        setAppState(AppState.AUTH);
      }
    });

    return () => {
      if (typeof unsubscribe === 'function') unsubscribe();
    };
  }, [loadData]);

  const handleRefresh = () => {
    if (user) loadData(user);
  };

  const handleGenerate = async (params: GenerateGreetingParams) => {
    if (!user) {
      alert("Please login to create cinematic greetings.");
      setAppState(AppState.AUTH);
      return;
    }

    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        setShowApiKeyDialog(true);
        return;
      }
    }

    setIsLoading(true);
    setAppState(AppState.LOADING);

    try {
      // Parallel generation of video and voice
      const [videoResult, voiceResult] = await Promise.all([
        generateGreetingVideo(params),
        generateGreetingVoice(params)
      ]);

      let videoUrl = "";
      let voiceUrl = "";
      let musicUrl = "";
      let newRecord: GreetingRecord | undefined;

      if (isFirebaseReady) {
        const uploads: Promise<string>[] = [
          uploadVideoToCloud(videoResult.blob, user.uid)
        ];

        if (voiceResult) {
          uploads.push(uploadAudioToCloud(voiceResult.blob, user.uid));
        }

        if (params.backgroundMusic) {
          uploads.push(uploadAudioToCloud(params.backgroundMusic.file, user.uid));
        }

        const results = await Promise.all(uploads);
        videoUrl = results[0];

        let idx = 1;
        if (voiceResult) {
          voiceUrl = results[idx++];
        }

        if (params.backgroundMusic) {
          musicUrl = results[idx++];
        } else {
          musicUrl = editingGreeting?.backgroundMusicUrl || "";
        }

        const recordData = {
          occasion: params.occasion,
          message: params.message,
          theme: params.theme,
          scenicDescription: params.scenicDescription,
          videoUrl: videoUrl,
          voice: params.voice,
          voiceUrl: voiceUrl,
          backgroundMusicUrl: musicUrl
        };

        if (editingGreeting) {
          await updateGreeting(editingGreeting.id, recordData);
          newRecord = { ...editingGreeting, ...recordData };
        } else {
          const docRef = await saveGreeting(user.uid, {
            ...recordData,
            userId: user.uid,
            createdAt: Date.now()
          });
          newRecord = { id: docRef.id, userId: user.uid, ...recordData, createdAt: Date.now() };
        }
        loadData(user);
      } else {
        videoUrl = URL.createObjectURL(videoResult.blob);
        voiceUrl = voiceResult ? `data:audio/pcm;base64,${voiceResult.base64}` : "";
        musicUrl = params.backgroundMusic ? URL.createObjectURL(params.backgroundMusic.file) : "";
      }

      setCurrentResult({ 
        url: videoUrl, 
        params, 
        record: newRecord,
        voiceUrl: voiceUrl,
        backgroundMusicUrl: musicUrl
      });
      setAppState(AppState.SUCCESS);
    } catch (e: any) {
      console.error("Production Error:", e);
      if (e.message?.includes("API Key") || e.message?.includes("not found")) {
        alert("Session or API key expired. Please re-select your Paid API Key.");
        if (window.aistudio) {
          setIsKeyConnected(false);
          setShowApiKeyDialog(true);
        }
      } else {
        alert("Production Error: " + e.message);
      }
      setAppState(user ? AppState.GALLERY : AppState.IDLE);
    } finally {
      setIsLoading(false);
    }
  };

  const handleEdit = (greeting: GreetingRecord) => {
    setEditingGreeting(greeting);
    setAppState(AppState.IDLE);
  };

  const handleSelectGreeting = (greeting: GreetingRecord) => {
    setCurrentResult({
      url: greeting.videoUrl,
      record: greeting,
      voiceUrl: greeting.voiceUrl,
      backgroundMusicUrl: greeting.backgroundMusicUrl,
      params: {
        occasion: greeting.occasion,
        message: greeting.message,
        theme: greeting.theme,
        scenicDescription: greeting.scenicDescription,
        voice: greeting.voice || VoiceGender.FEMALE, 
        userPhoto: null,
        scenePhoto: null,
        backgroundMusic: null,
        model: VeoModel.VEO_FAST,
        aspectRatio: AspectRatio.LANDSCAPE,
        extended: false
      }
    });
    setAppState(AppState.SUCCESS);
  };

  if (isAuthInitializing) {
    return (
      <div className="min-h-screen bg-black flex items-center justify-center">
        <div className="w-12 h-12 border-4 border-t-transparent border-blue-600 rounded-full animate-spin"></div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-black text-white flex flex-col font-sans selection:bg-blue-600/30">
      {showApiKeyDialog && <ApiKeyDialog onContinue={() => {
        if (window.aistudio) {
          window.aistudio.openSelectKey();
          setIsKeyConnected(true);
          setShowApiKeyDialog(false);
        }
      }} />}

      <HelpModal isOpen={showHelpModal} onClose={() => setShowHelpModal(false)} />

      <header className="px-6 py-5 flex justify-between items-center border-b border-white/5 bg-black/95 backdrop-blur-xl sticky top-0 z-50">
        <div 
          className="flex items-center gap-2 cursor-pointer group" 
          onClick={() => setAppState(user ? AppState.GALLERY : AppState.AUTH)}
        >
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center font-bold text-xl shadow-[0_0_20px_rgba(37,99,235,0.4)] group-hover:scale-105 transition-transform text-white">eG</div>
          <div className="flex flex-col">
            <h1 className="text-2xl font-black tracking-tight text-white leading-none">eGreetz</h1>
            <div className="flex items-center gap-1.5 mt-1.5">
              <span className={`flex h-2 w-2 rounded-full ${isKeyConnected ? 'bg-green-500' : 'bg-yellow-500 animate-pulse'}`}></span>
              <span className="text-[10px] text-gray-400 font-black tracking-widest uppercase">{isKeyConnected ? 'Studio Ready' : 'Connect Key'}</span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-4">
          {user && (
            <button onClick={handleRefresh} className="p-2 text-gray-400 hover:text-white transition-colors">
              <RefreshCw size={20} className={isLoading ? 'animate-spin' : ''} />
            </button>
          )}
          <button onClick={() => setShowHelpModal(true)} className="p-2 text-gray-400 hover:text-white transition-colors">
            <HelpCircle size={22} />
          </button>
          {user ? (
            <>
              <button onClick={() => { setEditingGreeting(null); setAppState(AppState.IDLE); }} className="flex items-center gap-2 px-6 py-2 bg-blue-600 rounded-full hover:bg-blue-500 transition-all font-bold text-sm text-white">
                <Plus size={16} strokeWidth={3} /> New Script
              </button>
              <button onClick={logout} className="p-2 text-gray-500 hover:text-white transition-colors"><LogOut size={20} /></button>
            </>
          ) : (
            <button onClick={loginWithGoogle} className="flex items-center gap-2 px-7 py-2.5 bg-white text-black font-black rounded-full hover:bg-gray-200 transition-all text-sm uppercase tracking-wider">
              <LogIn size={16} strokeWidth={3} /> Login
            </button>
          )}
        </div>
      </header>

      <main className="flex-grow flex flex-col items-center p-6 w-full max-w-6xl mx-auto">
        {!isFirebaseReady && (
          <div className="w-full max-w-4xl mb-6 p-4 bg-red-900/10 border border-red-500/20 rounded-2xl flex items-center gap-3 text-red-200 text-sm">
            <AlertCircle size={20} className="text-red-400" />
            <span>Cloud Sync Inactive. Sharing is limited.</span>
          </div>
        )}

        {appState === AppState.AUTH && (
          <div className="flex-grow flex flex-col items-center justify-center text-center max-w-3xl animate-in fade-in zoom-in duration-1000 mt-20">
            <h2 className="text-7xl font-black mb-8 leading-[1] text-white tracking-tighter">Cinematic <span className="text-blue-600">Reimagined.</span></h2>
            <p className="text-2xl text-gray-400 mb-12 leading-relaxed font-medium">Create Hollywood-grade greetings. Personal persistent storage for your cinematic legacy.</p>
            <button onClick={user ? () => setAppState(AppState.IDLE) : loginWithGoogle} className="px-16 py-6 bg-blue-600 rounded-3xl text-2xl font-black hover:bg-blue-500 transition-all shadow-2xl shadow-blue-600/40 uppercase tracking-widest text-white">
              {user ? 'Start Creating' : 'Login to Start'}
            </button>
          </div>
        )}

        {appState === AppState.GALLERY && user && (
          <div className="w-full h-full flex flex-col">
            <GreetingGallery 
              greetings={myGreetings} 
              receivedGreetings={receivedGreetings}
              onDelete={async (id) => { if(window.confirm("Delete?")) { await deleteGreeting(id); loadData(user); } }} 
              onEdit={handleEdit}
              onSelect={handleSelectGreeting}
              onCreateNew={() => { setEditingGreeting(null); setAppState(AppState.IDLE); }}
            />
          </div>
        )}

        {appState === AppState.IDLE && (
          <div className="w-full flex justify-center py-6">
            <GreetingCreator 
              onGenerate={handleGenerate} 
              onCancel={() => setAppState(user ? AppState.GALLERY : AppState.AUTH)} 
              initialData={editingGreeting}
            />
          </div>
        )}

        {appState === AppState.LOADING && <LoadingIndicator />}

        {appState === AppState.SUCCESS && currentResult && (
          <GreetingResult 
            result={currentResult} 
            onRestart={() => { setEditingGreeting(null); setAppState(AppState.IDLE); }} 
            onGoGallery={() => setAppState(AppState.GALLERY)}
            onInternalShare={async (email) => { 
              if(currentResult.record) {
                await sendToInternalUser(user?.displayName || "Friend", email, currentResult.record);
                alert("Shared!");
              }
            }}
          />
        )}
      </main>
    </div>
  );
};

