service firebase.storage {
  match /b/{bucket}/o {
    match /{allPaths=**} {
      // Allow any public user to view/play videos and audio
      allow read: if true;

      // Allow authenticated users to upload to their specific folders
      match /greetings/{userId}/{fileName} {
        allow write: if request.auth != null && request.auth.uid == userId;
      }

      match /audio/{userId}/{fileName} {
        allow write: if request.auth != null && request.auth.uid == userId;
      }
    }
  }
}

rules_version = '2';
service firebase.storage {
  match /b/{bucket}/o {
    match /{allPaths=**} {
      // Allow any public user to view/play videos and audio (Required for sharing)
      allow read: if true;

      // Allow authenticated users to upload video files to their specific folder
      match /greetings/{userId}/{fileName} {
        allow write: if request.auth != null && request.auth.uid == userId;
      }

      // Allow authenticated users to upload audio files to their specific folder
      match /audio/{userId}/{fileName} {
        allow write: if request.auth != null && request.auth.uid == userId;
      }
    }
  }
}

rules_version = '2';
service firebase.storage {
  match /b/{bucket}/o {

    // Explicit rules for greetings (video) folder
    // Matches patterns like: greetings/USER_ID/filename.mp4
    match /greetings/{userId}/{fileName} {
      allow read: if true;
      allow write: if request.auth != null && request.auth.uid == userId;
    }

    // Explicit rules for audio folder (voice & music uploads)
    // Matches patterns like: audio/USER_ID/filename.pcm
    match /audio/{userId}/{fileName} {
      allow read: if true;
      allow write: if request.auth != null && request.auth.uid == userId;
    }

    // Default catch-all to allow public reading of any other content
    // but prevents unauthorized writes to unknown paths
    match /{allPaths=**} {
      allow read: if true;
      allow write: if false;
    }
  }
}

