interface Props {
  initialParams: GenerateGreetingParams;
  videoUrl: string;
  initialVoiceUrl?: string;
  initialMusicUrl?: string;
  onSave: (params: GenerateGreetingParams, newVoiceBlob?: Blob, newMusicFile?: File) => void;
