  P720 = '720p',
  P1080 = '1080p',
}

export enum GenerationMode {
  TEXT_TO_VIDEO = 'Text to Video',
  FRAMES_TO_VIDEO = 'Frames to Video',
  REFERENCES_TO_VIDEO = 'References to Video',
  EXTEND_VIDEO = 'Extend Video',
}

export interface ImageFile {
  file: File;
  base64: string;
}

export interface AudioFile {
  file: File;
  base64: string;
}

export interface VideoFile {
  file: File;
  base64: string;
}

export interface GreetingRecord {
  id: string;
  userId: string;
  title?: string;
  occasion: Occasion;
  message: string;
  theme: GreetingTheme;
  scenicDescription?: string;
  videoUrl: string;
  voice?: VoiceGender;
  voiceUrl?: string; // Persistent synthesized voice
  backgroundMusicUrl?: string;
  trimStart?: number;
  trimEnd?: number;
  fadeOut?: boolean;
  createdAt: number;
  senderName?: string; // For shared records
  isReceived?: boolean;
}

export interface GenerateGreetingParams {
  title?: string;
  occasion: Occasion;
  message: string;
  theme: GreetingTheme;
  scenicDescription?: string;
  voice: VoiceGender;
  userPhoto: ImageFile | null;
  scenePhoto: ImageFile | null;
  backgroundMusic: AudioFile | null;
  model: VeoModel;
  aspectRatio: AspectRatio;
  extended: boolean;
  trimStart?: number;
  trimEnd?: number;
  fadeOut?: boolean;
}

export interface GenerateVideoParams {
  prompt: string;
  model: VeoModel;
  aspectRatio: AspectRatio;
  resolution: Resolution;
  mode: GenerationMode;
  startFrame: ImageFile | null;
  endFrame: ImageFile | null;
  referenceImages: ImageFile[];
  styleImage: ImageFile | null;
  inputVideo: VideoFile | null;
  inputVideoObject: Video | null;
  isLooping: boolean;
}

import React, { useState, useRef, useEffect } from 'react';
import { GenerateGreetingParams, VoiceGender, AudioFile } from '../types';
import { Play, Pause, Save, X, Music, Mic, Volume2, Scissors, Copy, RotateCcw, Sunrise, Sunset, Type } from 'lucide-react';
import { generateGreetingVoice } from '../services/geminiService';

interface Props {
  initialParams: GenerateGreetingParams;
  videoUrl: string;
  initialVoiceUrl?: string;
  initialMusicUrl?: string;
  onSave: (params: GenerateGreetingParams, newVoiceBlob?: Blob, newMusicFile?: File) => void;
  onSaveCopy: (params: GenerateGreetingParams, newVoiceBlob?: Blob, newMusicFile?: File) => void;
  onCancel: () => void;
}

const ProofStudio: React.FC<Props> = ({ 
  initialParams, 
  videoUrl, 
  initialVoiceUrl, 
  initialMusicUrl,
  onSave, 
  onSaveCopy, 
  onCancel 
}) => {
  // State
  const [title, setTitle] = useState(initialParams.title || initialParams.occasion || 'My Cinematic Greeting');
  const [message, setMessage] = useState(initialParams.message);
  const [voice, setVoice] = useState(initialParams.voice);
  const [trimStart, setTrimStart] = useState(initialParams.trimStart || 0);
  const [trimEnd, setTrimEnd] = useState(initialParams.trimEnd || 0);
  const [fadeOut, setFadeOut] = useState(initialParams.fadeOut || false);
  const [videoDuration, setVideoDuration] = useState(0);

  // Media State
  const [musicFile, setMusicFile] = useState<File | null>(null);
  const [tempVoiceUrl, setTempVoiceUrl] = useState<string | null>(initialVoiceUrl || null);
  const [tempVoiceBlob, setTempVoiceBlob] = useState<Blob | undefined>(undefined);
  const [isGeneratingVoice, setIsGeneratingVoice] = useState(false);

  // Playback State
  const [isPlaying, setIsPlaying] = useState(false);

  // Refs
  const videoRef = useRef<HTMLVideoElement>(null);
  const voiceAudioRef = useRef<HTMLAudioElement>(null);
  const musicAudioRef = useRef<HTMLAudioElement>(null);
  const animationFrameRef = useRef<number>();

  // Initialize duration
  const handleLoadedMetadata = () => {
    if (videoRef.current) {
      const dur = videoRef.current.duration;
      setVideoDuration(dur);
      if (trimEnd === 0 || trimEnd > dur) {
        setTrimEnd(dur);
      }
    }
  };

  // Sync Audio Playback with Video
  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;

    const syncAudio = () => {
      if (voiceAudioRef.current) {
        if (video.paused) {
          voiceAudioRef.current.pause();
        } else {
          // Sync voice to video time (relative to trim start if needed, but keeping simple alignment here)
          const audioTime = video.currentTime - trimStart; 
          if (audioTime >= 0) {
              voiceAudioRef.current.currentTime = audioTime;
              voiceAudioRef.current.play().catch(() => {});
          }
        }
      }
      if (musicAudioRef.current) {
         if (video.paused) {
             musicAudioRef.current.pause();
         } else {
             musicAudioRef.current.currentTime = video.currentTime;
             musicAudioRef.current.play().catch(() => {});
         }
      }
    };

    const handlePlay = () => { setIsPlaying(true); syncAudio(); };
    const handlePause = () => { setIsPlaying(false); syncAudio(); };
    const handleSeeking = () => { syncAudio(); };

    video.addEventListener('play', handlePlay);
    video.addEventListener('pause', handlePause);
    video.addEventListener('seeking', handleSeeking);

    return () => {
      video.removeEventListener('play', handlePlay);
      video.removeEventListener('pause', handlePause);
      video.removeEventListener('seeking', handleSeeking);
    };
  }, [trimStart]);

  // Real-time Loop for Trimming Check & Fading
  useEffect(() => {
    const loop = () => {
      if (videoRef.current) {
        const t = videoRef.current.currentTime;

        // Handle Loop/Stop at Trim End
        if (trimEnd > 0 && t >= trimEnd) {
          videoRef.current.pause();
          videoRef.current.currentTime = trimStart;
          setIsPlaying(false);
          // Reset opacity/vol
          videoRef.current.style.opacity = '1';
          if (voiceAudioRef.current) voiceAudioRef.current.volume = 1;
          if (musicAudioRef.current) musicAudioRef.current.volume = 1;
        }

        // Handle Fade Out
        if (fadeOut) {
          const fadeDuration = 3;
          const timeLeft = trimEnd - t;

          if (timeLeft <= fadeDuration) {
            // Calculate fade factor (1 to 0)
            const fadeFactor = Math.max(0, Math.min(1, timeLeft / fadeDuration));

            videoRef.current.style.opacity = fadeFactor.toString();
            if (voiceAudioRef.current) voiceAudioRef.current.volume = fadeFactor;
            if (musicAudioRef.current) musicAudioRef.current.volume = fadeFactor;
          } else {
            // Reset if scrubbed back before fade
            videoRef.current.style.opacity = '1';
            if (voiceAudioRef.current) voiceAudioRef.current.volume = 1;
            if (musicAudioRef.current) musicAudioRef.current.volume = 1;
          }
        } else {
          // Reset if fade disabled
          videoRef.current.style.opacity = '1';
          if (voiceAudioRef.current) voiceAudioRef.current.volume = 1;
          if (musicAudioRef.current) musicAudioRef.current.volume = 1;
        }
      }
      animationFrameRef.current = requestAnimationFrame(loop);
    };

    loop();
    return () => cancelAnimationFrame(animationFrameRef.current!);
  }, [trimStart, trimEnd, fadeOut]);

  // Regenerate Voice Preview
  const handleRegenerateVoice = async () => {
    setIsGeneratingVoice(true);
    try {
      const result = await generateGreetingVoice({
        ...initialParams,
        message,
        voice
      });
      if (result) {
        const url = URL.createObjectURL(result.blob);
        setTempVoiceUrl(url);
        setTempVoiceBlob(result.blob);
      }
    } catch (e) {
      console.error("Voice preview failed", e);
      alert("Failed to generate voice preview.");
    } finally {
      setIsGeneratingVoice(false);
    }
  };

  const handleMusicUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
      setMusicFile(e.target.files[0]);
    }
  };

  const constructParams = (): GenerateGreetingParams => ({
    ...initialParams,
    title,
    message,
    voice,
    trimStart,
    trimEnd,
    fadeOut
  });

  return (
    <div className="w-full max-w-6xl mx-auto bg-[#111114] border border-white/10 rounded-3xl overflow-hidden flex flex-col md:flex-row shadow-2xl animate-in fade-in slide-in-from-bottom-4">

      {/* Left: Preview Area */}
      <div className="flex-grow p-6 bg-black flex flex-col justify-center items-center relative border-r border-white/10">
        <div className="relative w-full aspect-video bg-black rounded-2xl overflow-hidden border border-white/10 shadow-lg group">
          <video 
            ref={videoRef}
            src={videoUrl}
            className="w-full h-full object-contain bg-black transition-opacity duration-75" // Added bg-black so fade to black works visually
            onLoadedMetadata={handleLoadedMetadata}
            playsInline
          />
          {/* Audio Elements (Hidden) */}
          {tempVoiceUrl && <audio ref={voiceAudioRef} src={tempVoiceUrl} />}
          <audio 
            ref={musicAudioRef} 
            src={musicFile ? URL.createObjectURL(musicFile) : initialMusicUrl} 
            loop 
          />

          {/* Custom Controls Overlay */}
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
            {!isPlaying && (
              <div className="p-4 bg-white/10 backdrop-blur-md rounded-full pointer-events-auto cursor-pointer hover:scale-110 transition-transform" onClick={() => videoRef.current?.play()}>
                <Play fill="white" size={32} />
              </div>
            )}
          </div>

          {/* Timeline / Trimmer */}
          <div className="absolute bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-black/90 to-transparent pointer-events-auto">
             <div className="flex items-center justify-between text-xs font-bold text-gray-400 mb-2 uppercase tracking-widest">
                <span>Start: {trimStart.toFixed(1)}s</span>
                <span>End: {trimEnd.toFixed(1)}s</span>
             </div>

             {/* Simple Range Slider Simulation */}
             <div className="relative h-2 bg-gray-800 rounded-full w-full">
                <div 
                  className="absolute h-full bg-blue-600/50 rounded-full"
                  style={{
                    left: `${(trimStart / videoDuration) * 100}%`,
                    width: `${((trimEnd - trimStart) / videoDuration) * 100}%`
                  }}
                />
                <input 
                   type="range" min="0" max={videoDuration} step="0.1"
                   value={trimStart}
                   onChange={(e) => {
                     const v = parseFloat(e.target.value);
                     if (v < trimEnd - 1) {
                        setTrimStart(v);
                        if (videoRef.current) videoRef.current.currentTime = v;
                     }
                   }}
                   className="absolute inset-0 w-full opacity-0 cursor-pointer z-20"
                />
                <input 
                   type="range" min="0" max={videoDuration} step="0.1"
                   value={trimEnd}
                   onChange={(e) => {
                     const v = parseFloat(e.target.value);
                     if (v > trimStart + 1) setTrimEnd(v);
                   }}
                   className="absolute inset-0 w-full opacity-0 cursor-pointer z-20"
                />
                {/* Visual Thumbs */}
                <div 
                   className="absolute top-1/2 -translate-y-1/2 w-4 h-4 bg-blue-500 rounded-full border-2 border-white pointer-events-none z-10 shadow-lg"
                   style={{ left: `${(trimStart / videoDuration) * 100}%` }}
                />
                <div 
                   className="absolute top-1/2 -translate-y-1/2 w-4 h-4 bg-blue-500 rounded-full border-2 border-white pointer-events-none z-10 shadow-lg"
                   style={{ left: `${(trimEnd / videoDuration) * 100}%` }}
                />
             </div>
          </div>
        </div>

        <div className="mt-6 flex gap-4 w-full">
           <button 
             onClick={() => onSave(constructParams(), tempVoiceBlob, musicFile || undefined)}
             className="flex-1 py-4 bg-blue-600 hover:bg-blue-500 text-white font-black uppercase tracking-widest rounded-xl flex items-center justify-center gap-2 transition-all shadow-lg shadow-blue-600/20"
           >
             <Save size={18} /> Save Changes
           </button>
           <button 
             onClick={() => onSaveCopy(constructParams(), tempVoiceBlob, musicFile || undefined)}
             className="flex-1 py-4 bg-purple-600 hover:bg-purple-500 text-white font-black uppercase tracking-widest rounded-xl flex items-center justify-center gap-2 transition-all shadow-lg shadow-purple-600/20"
           >
             <Copy size={18} /> Save as New
           </button>
        </div>
        <button onClick={onCancel} className="mt-4 text-gray-500 hover:text-white text-xs font-bold uppercase tracking-widest">
            Discard Changes
        </button>
      </div>

      {/* Right: Controls Area */}
      <div className="w-full md:w-96 p-6 md:p-8 bg-[#16161a] overflow-y-auto">
        <h2 className="text-2xl font-black text-white uppercase tracking-tight mb-8 flex items-center gap-2">
           <Scissors className="text-blue-500" /> Proof Studio
        </h2>

        <div className="space-y-8">

            {/* Project Title */}
            <div className="space-y-4">
                <label className="flex items-center gap-2 text-xs font-bold text-gray-500 uppercase tracking-widest">
                    <Type size={14} className="text-white" /> Project Title
                </label>
                <input
                    type="text"
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    className="w-full bg-black border border-white/10 rounded-xl px-4 py-3 text-sm font-bold text-white focus:outline-none focus:ring-2 focus:ring-blue-600 placeholder-gray-700"
                    placeholder="Enter a title..."
                />
            </div>

            {/* Script & Voice */}
            <div className="space-y-4">
                <label className="flex items-center gap-2 text-xs font-bold text-gray-500 uppercase tracking-widest">
                    <Mic size={14} className="text-blue-500" /> Script & Voice
                </label>
                <textarea 
                    value={message}
                    onChange={(e) => setMessage(e.target.value)}
                    className="w-full h-32 bg-black border border-white/10 rounded-xl p-4 text-sm text-white focus:ring-2 focus:ring-blue-600 focus:outline-none resize-none"
                />
                <div className="flex gap-2">
                    <select 
                        value={voice}
                        onChange={(e) => setVoice(e.target.value as VoiceGender)}
                        className="flex-grow bg-black border border-white/10 rounded-xl px-4 py-3 text-sm font-bold text-white focus:outline-none"
                    >
                        {Object.values(VoiceGender).map(v => (
                            <option key={v} value={v}>{v}</option>
                        ))}
                    </select>
                    <button 
                        onClick={handleRegenerateVoice}
                        disabled={isGeneratingVoice}
                        className="px-4 py-2 bg-white/5 border border-white/10 rounded-xl text-gray-300 hover:text-white hover:bg-white/10 transition-all"
                        title="Regenerate Voice Preview"
                    >
                        <RotateCcw size={18} className={isGeneratingVoice ? 'animate-spin' : ''} />
                    </button>
                </div>
            </div>

            {/* Background Music */}
            <div className="space-y-4">
                <label className="flex items-center gap-2 text-xs font-bold text-gray-500 uppercase tracking-widest">
                    <Music size={14} className="text-purple-500" /> Background Music
                </label>
                <div className="relative group">
                    <div className="w-full h-12 bg-black border border-white/10 rounded-xl flex items-center px-4">
                        <span className="text-xs text-gray-400 truncate">
                            {musicFile ? musicFile.name : 'Current Track'}
                        </span>
                    </div>
                    <input 
                        type="file" 
                        accept="audio/*" 
                        onChange={handleMusicUpload}
                        className="absolute inset-0 opacity-0 cursor-pointer"
                    />
                    <div className="absolute inset-y-0 right-0 flex items-center pr-3 pointer-events-none">
                        <div className="px-2 py-1 bg-white/10 rounded text-[10px] font-bold text-white">CHANGE</div>
                    </div>
                </div>
            </div>

            {/* Trimming & Fade Info */}
            <div className="space-y-4">
                <label className="flex items-center gap-2 text-xs font-bold text-gray-500 uppercase tracking-widest">
                    <Scissors size={14} className="text-green-500" /> Timing & Effects
                </label>
                <div className="p-4 bg-black/50 border border-white/5 rounded-xl space-y-4">
                    <p className="text-xs text-gray-400 leading-relaxed">
                      Use the sliders on the video to trim the intro and outro. 
                    </p>

                    <div className="flex items-center justify-between pt-2 border-t border-white/5">
                      <span className="text-xs font-bold text-gray-400">Duration</span>
                      <span className="text-white font-bold text-sm">{(trimEnd - trimStart).toFixed(1)}s</span>
                    </div>

                    <div className="flex items-center justify-between pt-2 border-t border-white/5">
                       <div className="flex items-center gap-2">
                          <Sunset size={14} className="text-orange-400" />
                          <span className="text-xs font-bold text-gray-400">Fade Out (Last 3s)</span>
                       </div>
                       <button 
                         onClick={() => setFadeOut(!fadeOut)}
                         className={`relative w-10 h-5 rounded-full transition-colors ${fadeOut ? 'bg-orange-500' : 'bg-gray-700'}`}
                       >
                         <div className={`absolute top-1 left-1 w-3 h-3 bg-white rounded-full transition-transform ${fadeOut ? 'translate-x-5' : ''}`} />
                       </button>
                    </div>
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

export default ProofStudio;

import React, { useState, useEffect, useCallback } from 'react';
import { 
  loginWithGoogle, 
  logout, 
  getUserGreetings, 
  saveGreeting, 
  updateGreeting, 
  deleteGreeting, 
  isFirebaseEnabled, 
  onAuthStateChangedListener,
  uploadVideoToCloud,
  uploadAudioToCloud,
  getReceivedGreetings,
  sendToInternalUser,
  sendToGroup,
  getGreetingById,
  getSharedGreetingById,
  type User 
} from './services/firebase';
import { AppState, GenerateGreetingParams, GreetingRecord, VeoModel, AspectRatio, VoiceGender, Occasion, GreetingTheme } from './types';
import GreetingCreator from './components/GreetingCreator';
import GreetingGallery from './components/GreetingGallery';
import GreetingResult from './components/GreetingResult';
import LoadingIndicator from './components/LoadingIndicator';
import ApiKeyDialog from './components/ApiKeyDialog';
import HelpModal from './components/HelpModal';
import LandingPage from './components/LandingPage';
import ProofStudio from './components/ProofStudio';
import { LogIn, LogOut, Plus, HelpCircle, RefreshCw, AlertCircle, Sparkles } from 'lucide-react';
import { generateGreetingVideo, generateGreetingVoice } from './services/geminiService';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [appState, setAppState] = useState<AppState>(AppState.AUTH);
  const [myGreetings, setMyGreetings] = useState<GreetingRecord[]>([]);
  const [receivedGreetings, setReceivedGreetings] = useState<GreetingRecord[]>([]);
  const [currentResult, setCurrentResult] = useState<{ 
    url: string; 
    params: GenerateGreetingParams; 
    record?: GreetingRecord; 
    audioUrl?: string; 
    voiceUrl?: string; 
    backgroundMusicUrl?: string 
  } | null>(null);
  const [editingGreeting, setEditingGreeting] = useState<GreetingRecord | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isAuthInitializing, setIsAuthInitializing] = useState(true);
  const [showApiKeyDialog, setShowApiKeyDialog] = useState(false);
  const [showHelpModal, setShowHelpModal] = useState(false);
  const [isKeyConnected, setIsKeyConnected] = useState(false);
  const [isFirebaseReady, setIsFirebaseReady] = useState(false);

  const loadData = useCallback(async (u: User) => {
    try {
      const [mine, received] = await Promise.all([
        getUserGreetings(u.uid),
        u.email ? getReceivedGreetings(u.email) : Promise.resolve([])
      ]);
      setMyGreetings(mine);
      setReceivedGreetings(received);
    } catch (err) {
      console.error("Failed to load user data:", err);
    }
  }, []);

  // Update theme class on body based on state
  useEffect(() => {
    const root = document.getElementById('root');
    if (root) {
      if (appState === AppState.AUTH) {
        root.classList.add('landing-mode');
      } else {
        root.classList.remove('landing-mode');
      }
    }
  }, [appState]);

  useEffect(() => {
    const init = async () => {
      setIsFirebaseReady(isFirebaseEnabled());

      // Check for Short URL parameters (?v=ID or ?s=ID)
      const urlParams = new URLSearchParams(window.location.search);
      const greetingId = urlParams.get('v');
      const sharedId = urlParams.get('s');

      if (greetingId || sharedId) {
        setIsLoading(true);
        try {
          const record = greetingId 
            ? await getGreetingById(greetingId) 
            : await getSharedGreetingById(sharedId!);

          if (record) {
            setCurrentResult({
              url: record.videoUrl,
              record,
              voiceUrl: record.voiceUrl,
              backgroundMusicUrl: record.backgroundMusicUrl,
              params: {
                title: record.title,
                occasion: record.occasion,
                message: record.message,
                theme: record.theme,
                scenicDescription: record.scenicDescription,
                voice: record.voice || VoiceGender.FEMALE,
                userPhoto: null,
                scenePhoto: null,
                backgroundMusic: null,
                model: VeoModel.VEO_FAST,
                aspectRatio: AspectRatio.LANDSCAPE,
                extended: false,
                trimStart: record.trimStart,
                trimEnd: record.trimEnd,
                fadeOut: record.fadeOut
              }
            });
            setAppState(AppState.VIEWER);
          } else {
            console.warn("Greeting not found");
          }
        } catch (err) {
          console.error("Error loading viewer:", err);
        } finally {
          setIsLoading(false);
        }
      }

      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setIsKeyConnected(hasKey);
      } else {
        const key = process.env.API_KEY;
        setIsKeyConnected(!!key);
      }
    };

    init();

    const unsubscribe = onAuthStateChangedListener((u) => {
      setUser(u);
      setIsAuthInitializing(false);

      // Only change state from AUTH if not already in VIEWER or SUCCESS
      const urlParams = new URLSearchParams(window.location.search);
      const hasLink = urlParams.has('v') || urlParams.has('s');

      if (u) {
        loadData(u);
        if (!hasLink) setAppState(AppState.GALLERY);
      } else {
        if (!hasLink) setAppState(AppState.AUTH);
      }
    });

    return () => {
      if (typeof unsubscribe === 'function') unsubscribe();
    };
  }, [loadData]);

  const handleRefresh = () => {
    if (user) loadData(user);
  };

  const handleGenerate = async (params: GenerateGreetingParams) => {
    if (!user) {
      alert("Please login to create cinematic greetings.");
      setAppState(AppState.AUTH);
      return;
    }

    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        setShowApiKeyDialog(true);
        return;
      }
    }

    setIsLoading(true);
    setAppState(AppState.LOADING);

    try {
      const [videoResult, voiceResult] = await Promise.all([
        generateGreetingVideo(params),
        generateGreetingVoice(params)
      ]);

      let videoUrl = "";
      let voiceUrl = "";
      let musicUrl = "";
      let newRecord: GreetingRecord | undefined;

      if (isFirebaseReady) {
        const uploads: Promise<string>[] = [
          uploadVideoToCloud(videoResult.blob, user.uid)
        ];

        if (voiceResult) {
          uploads.push(uploadAudioToCloud(voiceResult.blob, user.uid));
        }

        if (params.backgroundMusic) {
          uploads.push(uploadAudioToCloud(params.backgroundMusic.file, user.uid));
        }

        const results = await Promise.all(uploads);
        videoUrl = results[0];

        let idx = 1;
        if (voiceResult) {
          voiceUrl = results[idx++];
        }

        if (params.backgroundMusic) {
          musicUrl = results[idx++];
        } else {
          musicUrl = editingGreeting?.backgroundMusicUrl || "";
        }

        const recordData = {
          title: params.occasion, // Default title
          occasion: params.occasion,
          message: params.message,
          theme: params.theme,
          scenicDescription: params.scenicDescription,
          videoUrl: videoUrl,
          voice: params.voice,
          voiceUrl: voiceUrl,
          backgroundMusicUrl: musicUrl
        };

        if (editingGreeting) {
          await updateGreeting(editingGreeting.id, recordData);
          newRecord = { ...editingGreeting, ...recordData };
        } else {
          const docRef = await saveGreeting(user.uid, {
            ...recordData,
            userId: user.uid,
            createdAt: Date.now()
          });
          newRecord = { id: docRef.id, userId: user.uid, ...recordData, createdAt: Date.now() };
        }
        loadData(user);
      } else {
        videoUrl = URL.createObjectURL(videoResult.blob);
        voiceUrl = voiceResult ? `data:audio/pcm;base64,${voiceResult.base64}` : "";
        musicUrl = params.backgroundMusic ? URL.createObjectURL(params.backgroundMusic.file) : "";
      }

      setCurrentResult({ 
        url: videoUrl, 
        params, 
        record: newRecord,
        voiceUrl: voiceUrl,
        backgroundMusicUrl: musicUrl
      });
      setAppState(AppState.SUCCESS);
    } catch (e: any) {
      console.error("Production Error:", e);
      if (e.message?.includes("API Key") || e.message?.includes("not found")) {
        alert("Session or API key expired. Please re-select your Paid API Key.");
        if (window.aistudio) {
          setIsKeyConnected(false);
          setShowApiKeyDialog(true);
        }
      } else {
        alert("Production Error: " + e.message);
      }
      setAppState(user ? AppState.GALLERY : AppState.IDLE);
    } finally {
      setIsLoading(false);
    }
  };

  const handleEdit = (greeting: GreetingRecord) => {
    setEditingGreeting(greeting);
    setAppState(AppState.IDLE);
  };

  const handleSelectGreeting = (greeting: GreetingRecord) => {
    setCurrentResult({
      url: greeting.videoUrl,
      record: greeting,
      voiceUrl: greeting.voiceUrl,
      backgroundMusicUrl: greeting.backgroundMusicUrl,
      params: {
        title: greeting.title,
        occasion: greeting.occasion,
        message: greeting.message,
        theme: greeting.theme,
        scenicDescription: greeting.scenicDescription,
        voice: greeting.voice || VoiceGender.FEMALE, 
        userPhoto: null,
        scenePhoto: null,
        backgroundMusic: null,
        model: VeoModel.VEO_FAST,
        aspectRatio: AspectRatio.LANDSCAPE,
        extended: false,
        trimStart: greeting.trimStart,
        trimEnd: greeting.trimEnd,
        fadeOut: greeting.fadeOut
      }
    });
    setAppState(AppState.SUCCESS);
  };

  // Proof Studio Logic
  const handleProofSave = async (updatedParams: GenerateGreetingParams, newVoiceBlob?: Blob, newMusicFile?: File, asCopy: boolean = false) => {
    if (!user || !currentResult) return;
    setIsLoading(true);

    try {
        let voiceUrl = currentResult.voiceUrl;
        let musicUrl = currentResult.backgroundMusicUrl;

        // Upload new voice if generated
        if (newVoiceBlob && isFirebaseReady) {
            voiceUrl = await uploadAudioToCloud(newVoiceBlob, user.uid);
        } else if (newVoiceBlob) {
            // Local fallback
            voiceUrl = URL.createObjectURL(newVoiceBlob);
        }

        // Upload new music if selected
        if (newMusicFile && isFirebaseReady) {
            musicUrl = await uploadAudioToCloud(newMusicFile, user.uid);
        } else if (newMusicFile) {
            // Local fallback
            musicUrl = URL.createObjectURL(newMusicFile);
        }

        const recordData = {
            title: updatedParams.title || updatedParams.occasion,
            occasion: updatedParams.occasion,
            message: updatedParams.message,
            theme: updatedParams.theme,
            scenicDescription: updatedParams.scenicDescription,
            videoUrl: currentResult.url,
            voice: updatedParams.voice,
            voiceUrl: voiceUrl,
            backgroundMusicUrl: musicUrl,
            trimStart: updatedParams.trimStart,
            trimEnd: updatedParams.trimEnd,
            fadeOut: updatedParams.fadeOut
        };

        let finalRecord: GreetingRecord;

        if (isFirebaseReady) {
            if (asCopy) {
                // Create New
                 const docRef = await saveGreeting(user.uid, {
                    ...recordData,
                    userId: user.uid,
                    createdAt: Date.now()
                });
                finalRecord = { id: docRef.id, userId: user.uid, ...recordData, createdAt: Date.now() };
            } else if (currentResult.record) {
                // Update Existing
                await updateGreeting(currentResult.record.id, recordData);
                finalRecord = { ...currentResult.record, ...recordData };
            } else {
                 // Save for first time (if currentResult was transient)
                 const docRef = await saveGreeting(user.uid, {
                    ...recordData,
                    userId: user.uid,
                    createdAt: Date.now()
                });
                finalRecord = { id: docRef.id, userId: user.uid, ...recordData, createdAt: Date.now() };
            }
            loadData(user);
        } else {
            // Offline/Transient mode
            finalRecord = { 
                id: 'transient', 
                userId: 'local', 
                createdAt: Date.now(), 
                ...recordData 
            } as GreetingRecord;
        }

        // Update current result state
        setCurrentResult({
            url: currentResult.url,
            params: updatedParams,
            record: finalRecord,
            voiceUrl: voiceUrl,
            backgroundMusicUrl: musicUrl
        });

        setAppState(AppState.SUCCESS);

    } catch (e: any) {
        console.error("Proof Save Failed:", e);
        alert("Failed to save proof edits.");
    } finally {
        setIsLoading(false);
    }
  };

  const handleInternalShare = async (recipients: string[]) => {
    if (!currentResult?.record || !user) return;
    try {
      if (recipients.length === 1) {
        await sendToInternalUser(user.displayName || "Friend", recipients[0], currentResult.record);
      } else {
        await sendToGroup(user.displayName || "Friend", recipients, currentResult.record);
      }
      alert(`Greeting shared with ${recipients.length} ${recipients.length === 1 ? 'recipient' : 'recipients'}!`);
    } catch (err: any) {
      console.error("Share failed:", err);
      alert("Failed to share greeting.");
    }
  };

  if (isAuthInitializing) {
    return (
      <div className="min-h-screen bg-black flex items-center justify-center">
        <div className="w-12 h-12 border-4 border-t-transparent border-blue-600 rounded-full animate-spin"></div>
      </div>
    );
  }

  // Pure Viewer Mode (Public)
  if (appState === AppState.VIEWER && currentResult) {
    return (
      <div className="min-h-screen bg-black text-white flex flex-col items-center justify-center p-6">
        <div className="w-full max-w-4xl text-center mb-8">
           <div className="inline-flex p-3 bg-blue-600/20 rounded-2xl text-blue-500 mb-4">
              <Sparkles size={24} />
           </div>
           <h1 className="text-3xl font-black italic text-white uppercase tracking-tighter">You've received a greeting!</h1>
        </div>
        <GreetingResult 
          result={currentResult} 
          onRestart={() => setAppState(user ? AppState.GALLERY : AppState.AUTH)} 
          onGoGallery={() => setAppState(AppState.GALLERY)}
          isViewerOnly={true}
        />
        {!user && (
          <button 
            onClick={loginWithGoogle}
            className="mt-12 px-8 py-3 bg-white/5 border border-white/10 rounded-full text-xs font-black uppercase tracking-widest hover:bg-white/10 transition-all"
          >
            Create Your Own eGreetz
          </button>
        )}
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col font-sans selection:bg-blue-600/30 transition-colors">
      {showApiKeyDialog && <ApiKeyDialog onContinue={() => {
        if (window.aistudio) {
          window.aistudio.openSelectKey();
          setIsKeyConnected(true);
          setShowApiKeyDialog(false);
        }
      }} />}

      <HelpModal isOpen={showHelpModal} onClose={() => setShowHelpModal(false)} />

      {appState !== AppState.AUTH && (
        <header className="px-6 py-5 flex justify-between items-center border-b border-white/5 bg-black/95 backdrop-blur-xl sticky top-0 z-50">
          <div 
            className="flex items-center gap-2 cursor-pointer group" 
            onClick={() => {
              // Reset URL when going home
              window.history.pushState({}, '', '/');
              setAppState(user ? AppState.GALLERY : AppState.AUTH);
            }}
          >
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center font-bold text-xl shadow-[0_0_20px_rgba(37,99,235,0.4)] group-hover:scale-105 transition-transform text-white">eG</div>
            <div className="flex flex-col">
              <h1 className="text-2xl font-black tracking-tight text-white leading-none">eGreetz</h1>
              <div className="flex items-center gap-1.5 mt-1.5">
                <span className={`flex h-2 w-2 rounded-full ${isKeyConnected ? 'bg-green-500' : 'bg-yellow-500 animate-pulse'}`}></span>
                <span className="text-[10px] text-gray-400 font-black tracking-widest uppercase">{isKeyConnected ? 'Studio Ready' : 'Connect Key'}</span>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-4">
            {user && (
              <button onClick={handleRefresh} className="p-2 text-gray-400 hover:text-white transition-colors">
                <RefreshCw size={20} className={isLoading ? 'animate-spin' : ''} />
              </button>
            )}
            <button onClick={() => setShowHelpModal(true)} className="p-2 text-gray-400 hover:text-white transition-colors">
              <HelpCircle size={22} />
            </button>
            {user ? (
              <>
                <button onClick={() => { setEditingGreeting(null); setAppState(AppState.IDLE); }} className="flex items-center gap-2 px-6 py-2 bg-blue-600 rounded-full hover:bg-blue-500 transition-all font-bold text-sm text-white">
                  <Plus size={16} strokeWidth={3} /> New Script
                </button>
                <button onClick={logout} className="p-2 text-gray-500 hover:text-white transition-colors"><LogOut size={20} /></button>
              </>
            ) : (
              <button onClick={loginWithGoogle} className="flex items-center gap-2 px-7 py-2.5 bg-white text-black font-black rounded-full hover:bg-gray-200 transition-all text-sm uppercase tracking-wider">
                <LogIn size={16} strokeWidth={3} /> Login
              </button>
            )}
          </div>
        </header>
      )}

      <main className={`flex-grow flex flex-col items-center w-full ${appState === AppState.AUTH ? '' : 'p-6 max-w-6xl mx-auto'}`}>
        {appState !== AppState.AUTH && !isFirebaseReady && (
          <div className="w-full max-w-4xl mb-6 p-4 bg-red-900/10 border border-red-500/20 rounded-2xl flex items-center gap-3 text-red-200 text-sm">
            <AlertCircle size={20} className="text-red-400" />
            <span>Cloud Sync Inactive. Sharing is limited.</span>
          </div>
        )}

        {appState === AppState.AUTH ? (
          <LandingPage onLogin={loginWithGoogle} />
        ) : (
          <>
            {appState === AppState.GALLERY && user && (
              <div className="w-full h-full flex flex-col">
                <GreetingGallery 
                  greetings={myGreetings} 
                  receivedGreetings={receivedGreetings}
                  onDelete={async (id) => { if(window.confirm("Delete?")) { await deleteGreeting(id); loadData(user); } }} 
                  onEdit={handleEdit}
                  onSelect={handleSelectGreeting}
                  onCreateNew={() => { setEditingGreeting(null); setAppState(AppState.IDLE); }}
                />
              </div>
            )}

            {appState === AppState.IDLE && (
              <div className="w-full flex justify-center py-6">
                <GreetingCreator 
                  onGenerate={handleGenerate} 
                  onCancel={() => setAppState(user ? AppState.GALLERY : AppState.AUTH)} 
                  initialData={editingGreeting}
                />
              </div>
            )}

            {appState === AppState.LOADING && <LoadingIndicator />}

            {appState === AppState.PROOF_STUDIO && currentResult && (
               <div className="w-full flex justify-center py-6">
                 <ProofStudio
                    initialParams={currentResult.params}
                    videoUrl={currentResult.url}
                    initialVoiceUrl={currentResult.voiceUrl}
                    initialMusicUrl={currentResult.backgroundMusicUrl}
                    onSave={(p, v, m) => handleProofSave(p, v, m, false)}
                    onSaveCopy={(p, v, m) => handleProofSave(p, v, m, true)}
                    onCancel={() => setAppState(AppState.SUCCESS)}
                 />
               </div>
            )}

            {appState === AppState.SUCCESS && currentResult && (
              <GreetingResult 
                result={currentResult} 
                onRestart={() => { setEditingGreeting(null); setAppState(AppState.IDLE); }} 
                onGoGallery={() => setAppState(AppState.GALLERY)}
                onInternalShare={handleInternalShare}
                onEdit={() => setAppState(AppState.PROOF_STUDIO)}
              />
            )}
          </>
        )}
      </main>
    </div>
  );
};

